{
  "name": "MidiHost Pro Control",
  "description": "A professional-grade MIDI control surface for web browsers, inspired by Avid S1. Control DAWs like Pro Tools using virtual MIDI cables with high-precision faders, encoders, and transport controls.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MidiPort {
  id: string;
  name: string;
  manufacturer: string;
}

export enum ControlMode {
  UNIVERSAL = 'UNIVERSAL',
  HUI = 'PRO_TOOLS_HUI',
  MCU = 'MACKIE_CONTROL'
}

export interface ChannelData {
  id: number;
  name: string;
  fader: number; // 0-127
  pan: number;   // 0-127
  mute: boolean;
  solo: boolean;
  rec: boolean;
}

export interface AppState {
  inputs: MidiPort[];
  outputs: MidiPort[];
  selectedInputId: string | null;
  selectedOutputId: string | null;
  channels: ChannelData[];
  mode: ControlMode;
  isRecording: boolean;
  isPlaying: boolean;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMidiAssistance(query: string, mode: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User asks: ${query}. Current control mode: ${mode}. Provide brief, expert instructions on how to set up virtual MIDI cables (like loopMIDI or IAC) to control Pro Tools or other DAWs using this web interface. Keep it technical and helpful.`,
      config: {
        systemInstruction: "You are a professional audio engineer and MIDI specialist. You help users configure their web-based control surfaces with DAWs. Use concise markdown.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Could not fetch assistance. Check your internet connection.";
  }
}

import React from 'react';

interface FaderProps {
  value: number;
  onChange: (val: number) => void;
  label: string;
  channelId: number;
}

const Fader: React.FC<FaderProps> = ({ value, onChange, label, channelId }) => {
  return (
    <div className="flex flex-col items-center h-full w-20 bg-slate-900 border-x border-slate-800 p-2">
      <div className="oled-display text-[10px] w-full text-center py-1 mb-4 rounded border border-slate-700 h-12 flex flex-col justify-center overflow-hidden">
        <div className="opacity-70">CH {channelId + 1}</div>
        <div className="font-bold truncate">{label}</div>
        <div className="text-[8px] text-yellow-500">{( (value/127)*10 - 10 ).toFixed(1)} dB</div>
      </div>

      <div className="relative flex-grow flex justify-center items-center w-full py-4">
        {/* dB Scale */}
        <div className="absolute left-1 h-full flex flex-col justify-between text-[8px] text-slate-500 py-4 pointer-events-none">
          <span>+10</span>
          <span>+5</span>
          <span>0</span>
