          onChange={(e) => onChange(parseInt(e.target.value))}
          className="absolute appearance-none bg-transparent h-full w-12 cursor-pointer z-10"
          style={{ 
            writingMode: 'vertical-lr', 
            direction: 'rtl',
            WebkitAppearance: 'none'
          }}
        />
      </div>

      <div className="mt-4 w-full grid grid-cols-2 gap-1 px-1">
        <button className="bg-slate-800 hover:bg-slate-700 text-[10px] py-1 rounded border border-slate-600">SEL</button>
        <button className="bg-slate-800 hover:bg-slate-700 text-[10px] py-1 rounded border border-slate-600">CLR</button>
      </div>
