export default Fader;

import React, { useState, useEffect, useRef } from 'react';

interface KnobProps {
  value: number;
  onChange: (val: number) => void;
  label: string;
}

const Knob: React.FC<KnobProps> = ({ value, onChange, label }) => {
  const [isDragging, setIsDragging] = useState(false);
  const startY = useRef(0);
  const startVal = useRef(0);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    startY.current = e.clientY;
    startVal.current = value;
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging) return;
      const delta = startY.current - e.clientY;
      const newVal = Math.max(0, Math.min(127, startVal.current + delta));
      onChange(Math.round(newVal));
    };

    const handleMouseUp = () => setIsDragging(false);

    if (isDragging) {
      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      window.removeEventListener('mousemove', handleMouseMove);
      window.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, onChange]);

  const rotation = (value / 127) * 270 - 135;

  return (
    <div className="flex flex-col items-center gap-1 group">
      <div 
        className="relative w-12 h-12 rounded-full bg-slate-800 border-2 border-slate-700 cursor-ns-resize shadow-inner flex items-center justify-center"
        onMouseDown={handleMouseDown}
      >
        <div 
          className="absolute w-1 h-4 bg-cyan-400 rounded-full top-1 transition-transform duration-75"
          style={{ transform: `rotate(${rotation}deg)`, transformOrigin: 'bottom center', top: '15%' }}
        />
        <div className="w-8 h-8 rounded-full bg-slate-900 border border-slate-700 shadow-lg"></div>
      </div>
      <span className="text-[9px] uppercase font-semibold text-slate-400 group-hover:text-cyan-400 transition-colors">{label}</span>
      <span className="text-[8px] oled-display px-1 rounded">{value}</span>
    </div>
  );
};

export default Knob;

import React from 'react';

interface TransportProps {
  isPlaying: boolean;
  isRecording: boolean;
  onPlay: () => void;
  onStop: () => void;
  onRec: () => void;
  onPrev: () => void;
  onNext: () => void;
}

const Transport: React.FC<TransportProps> = ({ 
  isPlaying, isRecording, onPlay, onStop, onRec, onPrev, onNext 
}) => {
  return (
    <div className="flex items-center gap-3 bg-slate-950 p-4 rounded-xl border border-slate-800 shadow-2xl">
      <button onClick={onPrev} className="w-10 h-10 rounded-full bg-slate-800 hover:bg-slate-700 flex items-center justify-center text-slate-400">
        <i className="fas fa-step-backward"></i>
      </button>

      <button 
        onClick={onStop} 
        className={`w-12 h-12 rounded-full ${!isPlaying ? 'bg-slate-700 text-slate-300' : 'bg-slate-800 hover:bg-slate-700 text-slate-400'} flex items-center justify-center transition-all`}
      >
        <i className="fas fa-stop text-lg"></i>
      </button>

      <button 
        onClick={onPlay} 
        className={`w-14 h-14 rounded-full ${isPlaying ? 'bg-green-600 text-white shadow-[0_0_15px_rgba(22,163,74,0.5)]' : 'bg-slate-800 hover:bg-slate-700 text-green-500'} flex items-center justify-center transition-all`}
      >
        <i className="fas fa-play text-xl ml-1"></i>
      </button>

      <button 
        onClick={onRec} 
        className={`w-12 h-12 rounded-full ${isRecording ? 'bg-red-600 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.5)]' : 'bg-slate-800 hover:bg-slate-700 text-red-500'} flex items-center justify-center transition-all`}
      >
        <i className="fas fa-circle text-lg"></i>
      </button>

      <button onClick={onNext} className="w-10 h-10 rounded-full bg-slate-800 hover:bg-slate-700 flex items-center justify-center text-slate-400">
        <i className="fas fa-step-forward"></i>
      </button>

      <div className="ml-6 px-4 py-2 bg-black rounded-lg border border-slate-800 min-w-[120px] text-center">
        <div className="text-[10px] text-slate-500 uppercase font-bold tracking-widest mb-1">Timecode</div>
        <div className="oled-display text-xl font-mono">00:01:24:12</div>
      </div>
    </div>
  );
};

export default Transport;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Audio ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [mode, setMode] = useState<ControlMode>(ControlMode.UNIVERSAL);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [aiHelperText, setAiHelperText] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  // MIDI Setup
  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('MIDI access denied or not supported.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((port) => {
      inputPorts.push({ id: port.id, name: port.name || 'Unnamed Input', manufacturer: port.manufacturer || '' });
    });
    access.outputs.forEach((port) => {
      outputPorts.push({ id: port.id, name: port.name || 'Unnamed Output', manufacturer: port.manufacturer || '' });
    });
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  // Handle incoming MIDI messages from DAW
  useEffect(() => {
    if (!midiAccess || !selectedInput) return;
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: any) => {
      const [status, d1, d2] = event.data;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      // Simple CC mapping for visual feedback from DAW
      if (type === 0xb0) { // Control Change
        if (d1 >= 0 && d1 < CHANNELS_COUNT) {
          setChannels(prev => prev.map(ch => ch.id === d1 ? { ...ch, fader: d2 } : ch));
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput]);

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
    }
  }, [midiAccess, selectedOutput]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    setChannels(prev => prev.map(ch => {
      if (ch.id === id) {
        const updated = { ...ch, ...updates };
        if (updates.fader !== undefined) sendMidi(0xb0, id, updates.fader);
        if (updates.pan !== undefined) sendMidi(0xb0, id + 20, updates.pan);
        if (updates.mute !== undefined) sendMidi(0x90, id + 40, updates.mute ? 127 : 0);
        if (updates.solo !== undefined) sendMidi(0x90, id + 60, updates.solo ? 127 : 0);
        return updated;
      }
      return ch;
    }));
  };

  const handleAiAsk = async () => {
    setIsAiLoading(true);
    const help = await getMidiAssistance("How do I configure Pro Tools to work with this virtual cable?", mode);
    setAiHelperText(help);
    setIsAiLoading(false);
    setShowHelper(true);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-slate-950 font-sans">
      {/* Top Bar / Metadata */}
      <header className="flex items-center justify-between px-6 py-4 bg-slate-900 border-b border-slate-800 shadow-md">
        <div className="flex items-center gap-4">
          <div className="bg-cyan-500 p-2 rounded-lg text-slate-950">
            <i className="fas fa-wave-square text-xl"></i>
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight text-slate-100">MidiHost <span className="text-cyan-400">Pro</span></h1>
            <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">Virtual Surface Controller</p>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <div className="flex flex-col">
            <label className="text-[10px] uppercase text-slate-500 font-bold mb-1">MIDI Input</label>
            <select 
              className="bg-slate-800 text-xs px-3 py-1.5 rounded border border-slate-700 focus:outline-none focus:ring-1 focus:ring-cyan-500 w-48"
              value={selectedInput}
              onChange={(e) => setSelectedInput(e.target.value)}
            >
              <option value="">Select Input...</option>
              {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>

          <div className="flex flex-col">
            <label className="text-[10px] uppercase text-slate-500 font-bold mb-1">MIDI Output</label>
            <select 
              className="bg-slate-800 text-xs px-3 py-1.5 rounded border border-slate-700 focus:outline-none focus:ring-1 focus:ring-cyan-500 w-48"
              value={selectedOutput}
              onChange={(e) => setSelectedOutput(e.target.value)}
            >
              <option value="">Select Output...</option>
              {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>

          <div className="flex flex-col">
            <label className="text-[10px] uppercase text-slate-500 font-bold mb-1">Emulation</label>
            <select 
              className="bg-slate-800 text-xs px-3 py-1.5 rounded border border-slate-700 focus:outline-none focus:ring-1 focus:ring-cyan-500"
              value={mode}
              onChange={(e) => setMode(e.target.value as ControlMode)}
            >
              <option value={ControlMode.UNIVERSAL}>Universal CC</option>
              <option value={ControlMode.HUI}>Pro Tools HUI</option>
              <option value={ControlMode.MCU}>Mackie Control</option>
            </select>
          </div>

          <button 
            onClick={handleAiAsk}
            className="flex items-center gap-2 bg-slate-800 hover:bg-slate-700 px-4 py-2 rounded-lg border border-slate-600 transition-all group"
          >
            <i className={`fas fa-microchip ${isAiLoading ? 'animate-spin' : ''} text-cyan-400 group-hover:scale-110`}></i>
            <span className="text-xs font-bold uppercase">Setup Help</span>
          </button>
        </div>
      </header>

      {/* Main Control Surface */}
      <main className="flex-grow flex p-6 gap-6 relative">
        {/* Channel Strips Area */}
        <div className="flex-grow bg-slate-900 rounded-2xl border border-slate-800 p-1 flex overflow-x-auto shadow-inner">
          {channels.map((ch, idx) => (
            <div key={ch.id} className="flex flex-col border-r border-slate-800 last:border-r-0 min-w-[100px]">
              {/* Top Controls (Knobs) */}
              <div className="p-4 border-b border-slate-800 bg-slate-950/50 flex flex-col gap-4 items-center">
                 <Knob 
                    label="Pan" 
                    value={ch.pan} 
                    onChange={(v) => updateChannel(ch.id, { pan: v })} 
                 />
                 <div className="flex gap-2 w-full justify-center">
                   <button 
                    onClick={() => updateChannel(ch.id, { solo: !ch.solo })}
                    className={`text-[9px] font-bold w-10 py-1 rounded border transition-colors ${ch.solo ? 'bg-yellow-500 border-yellow-400 text-black' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
                   >
                     SOLO
                   </button>
                   <button 
                    onClick={() => updateChannel(ch.id, { mute: !ch.mute })}
                    className={`text-[9px] font-bold w-10 py-1 rounded border transition-colors ${ch.mute ? 'bg-red-500 border-red-400 text-white' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
                   >
                     MUTE
                   </button>
                 </div>
                 <button 
                  onClick={() => updateChannel(ch.id, { rec: !ch.rec })}
                  className={`text-[9px] font-bold w-full py-1 rounded border transition-colors ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-400'}`}
                 >
                   RECORD ARM
                 </button>
              </div>

              {/* Fader Area */}
              <div className="flex-grow">
                <Fader 
                  channelId={idx} 
                  label={ch.name} 
                  value={ch.fader} 
                  onChange={(v) => updateChannel(ch.id, { fader: v })} 
                />
              </div>
            </div>
          ))}
        </div>

        {/* Master Section & Transport */}
        <aside className="w-80 flex flex-col gap-6">
          <div className="bg-slate-900 rounded-2xl border border-slate-800 p-6 flex-grow shadow-lg">
             <h3 className="text-xs font-black text-slate-500 uppercase tracking-tighter mb-4">Master Section</h3>
             <div className="flex flex-col items-center justify-center h-full gap-8">
                <div className="w-full">
                  <div className="flex justify-between text-[10px] text-slate-400 mb-2 px-1">
                    <span>MASTER L/R</span>
                    <span className="text-green-400 font-mono">-1.2 dB</span>
                  </div>
                  <div className="h-64 w-full bg-black rounded-lg border border-slate-800 p-1 flex gap-1 items-end">
                    <div className="flex-grow bg-gradient-to-t from-green-500 via-yellow-400 to-red-500 w-1/2 rounded" style={{ height: '85%' }}></div>
                    <div className="flex-grow bg-gradient-to-t from-green-500 via-yellow-400 to-red-500 w-1/2 rounded" style={{ height: '82%' }}></div>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-3 w-full">
                  <button className="bg-slate-800 py-3 rounded-lg text-xs font-bold border border-slate-700 hover:bg-slate-700 active:scale-95 transition-all">FLIP</button>
                  <button className="bg-slate-800 py-3 rounded-lg text-xs font-bold border border-slate-700 hover:bg-slate-700 active:scale-95 transition-all">MIX</button>
                  <button className="bg-slate-800 py-3 rounded-lg text-xs font-bold border border-slate-700 hover:bg-slate-700 active:scale-95 transition-all">EDIT</button>
                  <button className="bg-slate-800 py-3 rounded-lg text-xs font-bold border border-slate-700 hover:bg-slate-700 active:scale-95 transition-all">ENV</button>
                </div>
             </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { 
              setIsPlaying(true); 
              sendMidi(0xb0, 110, 127); // Standard DAW Play CC
            }}
            onStop={() => { 
              setIsPlaying(false); 
              setIsRecording(false);
              sendMidi(0xb0, 111, 127); // Standard DAW Stop CC
            }}
            onRec={() => { 
              setIsRecording(!isRecording); 
              sendMidi(0xb0, 112, 127); // Standard DAW Rec CC
            }}
            onPrev={() => sendMidi(0xb0, 113, 127)}
            onNext={() => sendMidi(0xb0, 114, 127)}
          />
        </aside>
      </main>

      {/* Helper Panel Overlay */}
      {showHelper && (
        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm z-50 flex items-center justify-center p-12">
          <div className="bg-slate-900 w-full max-w-2xl rounded-2xl border border-slate-700 shadow-2xl overflow-hidden flex flex-col max-h-full">
            <div className="px-6 py-4 bg-slate-800 border-b border-slate-700 flex justify-between items-center">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <i className="fas fa-magic text-cyan-400"></i> Smart Configuration Assistant
              </h2>
              <button onClick={() => setShowHelper(false)} className="text-slate-400 hover:text-white transition-colors">
                <i className="fas fa-times text-xl"></i>
              </button>
            </div>
            <div className="p-8 overflow-y-auto text-slate-300 prose prose-invert max-w-none">
              <div className="whitespace-pre-wrap font-mono text-sm bg-black/30 p-4 rounded-lg border border-slate-800">
                {aiHelperText}
              </div>
              <div className="mt-6 flex justify-end">
                <button 
                  onClick={() => setShowHelper(false)}
                  className="bg-cyan-600 hover:bg-cyan-500 text-white font-bold py-2 px-6 rounded-lg transition-colors"
                >
                  Got it!
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer / Status */}
      <footer className="bg-slate-950 border-t border-slate-900 px-6 py-2 flex justify-between items-center text-[10px] text-slate-500">
        <div className="flex gap-4 items-center">
          <span className="flex items-center gap-1">
            <span className={`w-2 h-2 rounded-full ${midiAccess ? 'bg-green-500' : 'bg-red-500'}`}></span>
            MIDI ENGINE: {midiAccess ? 'READY' : 'OFFLINE'}
          </span>
          <span className="flex items-center gap-1">
            <span className={`w-2 h-2 rounded-full ${selectedOutput ? 'bg-green-500' : 'bg-slate-700'}`}></span>
            LINK STATUS: {selectedOutput ? 'CONNECTED' : 'DISCONNECTED'}
          </span>
        </div>
        <div className="font-mono text-slate-600">
          PRO TOOLS | WEB HUI v1.0.4 | LATENCY: 3ms
        </div>
      </footer>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export async function getMidiAssistance(query: string, mode: string) {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `User asks: ${query}. Current control mode: ${mode}. Provide brief, expert instructions on how to set up REAPER (Preferences > Control/OSC/web) using Mackie Control Universal (MCU) with this web interface and virtual MIDI cables (like loopMIDI or IAC). Explain how to enable the MIDI ports in REAPER.`,
      config: {
        systemInstruction: "You are a REAPER DAW expert and MIDI specialist. You help users configure their web-based control surfaces. Use concise markdown and focus on REAPER-specific terminology like 'Action List', 'Control Surface Settings', and 'Track Banking'.",
      }
    });
    return response.text;
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Could not fetch assistance. Check your internet connection.";
  }
}

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [aiHelperText, setAiHelperText] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('MIDI access denied. Please enable MIDI in your browser settings.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((port) => {
      inputPorts.push({ id: port.id, name: port.name || 'Input', manufacturer: port.manufacturer || '' });
    });
    access.outputs.forEach((port) => {
      outputPorts.push({ id: port.id, name: port.name || 'Output', manufacturer: port.manufacturer || '' });
    });
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
    }
  }, [midiAccess, selectedOutput]);

  // Protocolo MCU Fader (Pitch Bend para alta resolución)
  const sendFaderMidi = useCallback((channel: number, value: number) => {
    if (mode === ControlMode.MCU) {
      // MCU usa Pitch Bend (0xE0 - 0xE7) para los faders 1-8
      // Escalamos 0-127 a 0-16383 (aunque aquí simplificamos a 7 bits msb para compatibilidad básica)
      const lsb = 0; 
      const msb = value;
      sendMidi(0xE0 + channel, lsb, msb);
    } else {
      sendMidi(0xB0, channel, value);
    }
  }, [mode, sendMidi]);

  // Protocolo MCU Botones (Notas MIDI)
  const sendButtonMidi = useCallback((type: 'REC' | 'SOLO' | 'MUTE' | 'SELECT', channel: number, state: boolean) => {
    if (mode === ControlMode.MCU) {
      let note = 0;
      switch(type) {
        case 'REC': note = 0x00 + channel; break;
        case 'SOLO': note = 0x08 + channel; break;
        case 'MUTE': note = 0x10 + channel; break;
        case 'SELECT': note = 0x18 + channel; break;
      }
      sendMidi(0x90, note, state ? 127 : 0);
    } else {
      const ccBase = type === 'MUTE' ? 40 : type === 'SOLO' ? 60 : 80;
      sendMidi(0x90, ccBase + channel, state ? 127 : 0);
    }
  }, [mode, sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) return;
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: any) => {
      const [status, d1, d2] = event.data;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      // Escuchar Pitch Bend (Retroalimentación de REAPER para faders MCU)
      if (type === 0xE0 && mode === ControlMode.MCU) {
        setChannels(prev => prev.map(ch => ch.id === channel ? { ...ch, fader: d2 } : ch));
      }
      // Escuchar Notas (Retroalimentación para botones MCU)
      else if (type === 0x90 && mode === ControlMode.MCU) {
        if (d1 >= 0x10 && d1 <= 0x17) { // Mutes
          setChannels(prev => prev.map(ch => ch.id === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
        } else if (d1 >= 0x08 && d1 <= 0x0F) { // Solos
          setChannels(prev => prev.map(ch => ch.id === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput, mode]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    setChannels(prev => prev.map(ch => {
      if (ch.id === id) {
        if (updates.fader !== undefined) sendFaderMidi(id, updates.fader);
        if (updates.mute !== undefined) sendButtonMidi('MUTE', id, updates.mute);
        if (updates.solo !== undefined) sendButtonMidi('SOLO', id, updates.solo);
        if (updates.rec !== undefined) sendButtonMidi('REC', id, updates.rec);
        if (updates.pan !== undefined) sendMidi(0xB0, id + 16, updates.pan); // MCU Pan es V-Pot CC 16-23
        return { ...ch, ...updates };
      }
      return ch;
    }));
  };

  const handleAiAsk = async () => {
    setIsAiLoading(true);
    const help = await getMidiAssistance("Cómo configurar REAPER con Mackie Control Universal y loopMIDI", mode);
    setAiHelperText(help);
    setIsAiLoading(false);
    setShowHelper(true);
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#1a1a1a] text-slate-200 font-sans">
      {/* Header Optimizado Reaper */}
      <header className="flex items-center justify-between px-6 py-3 bg-[#2a2a2a] border-b border-[#111] shadow-xl">
        <div className="flex items-center gap-4">
          <div className="bg-[#526d4f] p-2 rounded-lg text-white shadow-inner border border-[#3e523b]">
            <i className="fas fa-compact-disc text-xl animate-spin-slow"></i>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter text-white">REAPER<span className="text-[#526d4f]">HOST</span></h1>
            <p className="text-[9px] text-slate-400 uppercase tracking-widest font-bold">Advanced MCU Controller</p>
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex flex-col">
            <label className="text-[9px] uppercase text-slate-500 font-bold mb-1">Midi In (Virtual)</label>
            <select 
              className="bg-[#111] text-xs px-2 py-1.5 rounded border border-[#444] text-[#526d4f] font-bold focus:ring-1 focus:ring-[#526d4f] outline-none w-44"
              value={selectedInput}
              onChange={(e) => setSelectedInput(e.target.value)}
            >
              <option value="">None</option>
              {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>

          <div className="flex flex-col">
            <label className="text-[9px] uppercase text-slate-500 font-bold mb-1">Midi Out (To Reaper)</label>
            <select 
              className="bg-[#111] text-xs px-2 py-1.5 rounded border border-[#444] text-[#526d4f] font-bold focus:ring-1 focus:ring-[#526d4f] outline-none w-44"
              value={selectedOutput}
              onChange={(e) => setSelectedOutput(e.target.value)}
            >
              <option value="">None</option>
              {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>

          <div className="flex flex-col">
            <label className="text-[9px] uppercase text-slate-500 font-bold mb-1">Protocol</label>
            <select 
              className="bg-[#111] text-xs px-2 py-1.5 rounded border border-[#444] text-white font-bold"
              value={mode}
              onChange={(e) => setMode(e.target.value as ControlMode)}
            >
              <option value={ControlMode.MCU}>Reaper (MCU)</option>
              <option value={ControlMode.HUI}>Pro Tools (HUI)</option>
              <option value={ControlMode.UNIVERSAL}>Generic CC</option>
            </select>
          </div>

          <button 
            onClick={handleAiAsk}
            className="flex items-center gap-2 bg-[#333] hover:bg-[#444] px-4 py-2 rounded border border-[#555] transition-all group mt-2"
          >
            <i className={`fas fa-robot ${isAiLoading ? 'animate-bounce' : ''} text-[#526d4f]`}></i>
            <span className="text-[10px] font-bold">REAPER SETUP</span>
          </button>
        </div>
      </header>

      {/* Surface principal */}
      <main className="flex-grow flex p-4 gap-4 bg-[#111]">
        <div className="flex-grow bg-[#222] rounded-xl border border-[#333] p-1 flex overflow-x-auto shadow-2xl">
          {channels.map((ch, idx) => (
            <div key={ch.id} className="flex flex-col border-r border-[#111] last:border-r-0 min-w-[95px] bg-[#2a2a2a]">
              <div className="p-3 border-b border-[#111] bg-[#1a1a1a] flex flex-col gap-3 items-center">
                 <Knob 
                    label="PAN" 
                    value={ch.pan} 
                    onChange={(v) => updateChannel(ch.id, { pan: v })} 
                 />
                 <div className="flex flex-col gap-1 w-full px-1">
                   <button 
                    onClick={() => updateChannel(ch.id, { solo: !ch.solo })}
                    className={`text-[10px] font-black py-1.5 rounded border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black shadow-[0_0_10px_rgba(202,138,4,0.4)]' : 'bg-[#333] border-[#444] text-slate-500'}`}
                   >
                     SOLO
                   </button>
                   <button 
                    onClick={() => updateChannel(ch.id, { mute: !ch.mute })}
                    className={`text-[10px] font-black py-1.5 rounded border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white shadow-[0_0_10px_rgba(185,28,28,0.4)]' : 'bg-[#333] border-[#444] text-slate-500'}`}
                   >
                     MUTE
                   </button>
                   <button 
                    onClick={() => updateChannel(ch.id, { rec: !ch.rec })}
                    className={`text-[10px] font-black py-1.5 rounded border transition-all mt-1 ${ch.rec ? 'bg-red-600 border-red-400 text-white animate-pulse' : 'bg-[#1a1a1a] border-[#444] text-red-900'}`}
                   >
                     ARM
                   </button>
                 </div>
              </div>

              <div className="flex-grow">
                <Fader 
                  channelId={idx} 
                  label={ch.name} 
                  value={ch.fader} 
                  onChange={(v) => updateChannel(ch.id, { fader: v })} 
                />
              </div>
            </div>
          ))}
        </div>

        {/* Master & Reaper Transport */}
        <aside className="w-72 flex flex-col gap-4">
          <div className="bg-[#2a2a2a] rounded-xl border border-[#333] p-5 flex-grow shadow-lg">
             <div className="flex justify-between items-center mb-4">
               <h3 className="text-[10px] font-black text-[#526d4f] uppercase tracking-widest">Master Meter</h3>
               <div className="flex gap-1">
                 <div className="w-1.5 h-1.5 rounded-full bg-green-500"></div>
                 <div className="w-1.5 h-1.5 rounded-full bg-red-500 animate-ping"></div>
               </div>
             </div>

             <div className="h-4/5 w-full bg-[#111] rounded border border-[#444] p-1.5 flex gap-1 items-end relative overflow-hidden">
                <div className="absolute inset-0 flex flex-col justify-between p-2 pointer-events-none opacity-20">
                  {[0,-6,-12,-18,-24,-36,-48].map(db => <div key={db} className="w-full border-t border-white text-[8px]">{db}</div>)}
                </div>
                <div className="flex-grow bg-gradient-to-t from-[#2a4d2e] via-[#526d4f] to-red-600 w-1/2 rounded-sm" style={{ height: '78%' }}></div>
                <div className="flex-grow bg-gradient-to-t from-[#2a4d2e] via-[#526d4f] to-red-600 w-1/2 rounded-sm" style={{ height: '74%' }}></div>
             </div>

             <div className="mt-4 grid grid-cols-2 gap-2">
                <button className="bg-[#333] py-2 rounded text-[9px] font-bold border border-[#444] hover:bg-[#444]">AUTOMATION</button>
                <button className="bg-[#333] py-2 rounded text-[9px] font-bold border border-[#444] hover:bg-[#444]">MARKER</button>
             </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { 
              setIsPlaying(true); 
              if(mode === ControlMode.MCU) sendMidi(0x90, 0x5E, 127); // Play Note
              else sendMidi(0xB0, 110, 127);
            }}
            onStop={() => { 
              setIsPlaying(false); 
              setIsRecording(false);
              if(mode === ControlMode.MCU) sendMidi(0x90, 0x5D, 127); // Stop Note
              else sendMidi(0xB0, 111, 127);
            }}
            onRec={() => { 
              setIsRecording(!isRecording); 
              if(mode === ControlMode.MCU) sendMidi(0x90, 0x5F, 127); // Record Note
              else sendMidi(0xB0, 112, 127);
            }}
            onPrev={() => mode === ControlMode.MCU ? sendMidi(0x90, 0x5B, 127) : sendMidi(0xB0, 113, 127)}
            onNext={() => mode === ControlMode.MCU ? sendMidi(0x90, 0x5C, 127) : sendMidi(0xB0, 114, 127)}
          />
        </aside>
      </main>

      {/* Helper Panel */}
      {showHelper && (
        <div className="absolute inset-0 bg-black/80 backdrop-blur-md z-50 flex items-center justify-center p-8">
          <div className="bg-[#2a2a2a] w-full max-w-xl rounded-xl border border-[#444] shadow-[0_0_50px_rgba(0,0,0,0.8)] overflow-hidden">
            <div className="px-6 py-4 bg-[#1a1a1a] border-b border-[#333] flex justify-between items-center">
              <h2 className="text-sm font-black text-[#526d4f] flex items-center gap-2 tracking-widest uppercase">
                <i className="fas fa-cog"></i> Reaper Configuration
              </h2>
              <button onClick={() => setShowHelper(false)} className="text-slate-500 hover:text-white">
                <i className="fas fa-times"></i>
              </button>
            </div>
            <div className="p-6 overflow-y-auto max-h-[70vh]">
              <div className="bg-[#111] p-5 rounded-lg border border-[#333] text-sm font-mono text-green-500 leading-relaxed">
                {aiHelperText}
              </div>
            </div>
            <div className="p-4 bg-[#1a1a1a] flex justify-end">
                <button onClick={() => setShowHelper(false)} className="bg-[#526d4f] px-6 py-2 rounded text-xs font-bold text-white uppercase">Cerrar</button>
            </div>
          </div>
        </div>
      )}

      {/* StatusBar */}
      <footer className="bg-[#0a0a0a] border-t border-[#222] px-4 py-1.5 flex justify-between items-center text-[9px] text-slate-500 font-bold tracking-widest">
        <div className="flex gap-6 items-center">
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${midiAccess ? 'bg-green-500 shadow-[0_0_5px_green]' : 'bg-red-500'}`}></div>
            MIDI: {midiAccess ? 'ON' : 'OFF'}
          </div>
          <div className="flex items-center gap-2">
            <div className={`w-2 h-2 rounded-full ${selectedOutput ? 'bg-[#526d4f] shadow-[0_0_5px_#526d4f]' : 'bg-slate-800'}`}></div>
            REAPER LINK: {selectedOutput ? 'ACTIVE' : 'WAITING'}
          </div>
        </div>
        <div className="opacity-40">
          MCU PROTOCOL v2.0 | REAPER OPTIMIZED | 14-BIT PITCH BEND ENABLED
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [aiHelperText, setAiHelperText] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  // Refs para prevenir bucles de retroalimentación
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const lastSentTimes = useRef<number[]>(new Array(CHANNELS_COUNT).fill(0));

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: MIDI no soportado.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
    }
  }, [midiAccess, selectedOutput]);

  const sendFaderMidi = useCallback((channel: number, value: number) => {
    // Evitar envíos redundantes si el valor es el mismo que el último enviado
    if (lastSentValues.current[channel] === value) return;

    lastSentValues.current[channel] = value;
    lastSentTimes.current[channel] = Date.now();

    if (mode === ControlMode.MCU) {
      // MCU utiliza Pitch Bend para faders (E0..E7). 
      // Usamos el valor de 7 bits en el MSB para compatibilidad simple con el fader visual.
      sendMidi(0xE0 + channel, 0, value);
    } else {
      sendMidi(0xB0, channel, value);
    }
  }, [mode, sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) return;
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const [status, d1, d2] = event.data as any;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      // 1. Filtrar Retroalimentación de Faders (Pitch Bend en MCU)
      if (type === 0xE0 && mode === ControlMode.MCU) {
        if (channel < CHANNELS_COUNT) {
          const now = Date.now();
          // Si el mensaje llega muy rápido después de haberlo enviado nosotros, lo ignoramos
          if (now - lastSentTimes.current[channel] < 150 && d2 === lastSentValues.current[channel]) {
            return; 
          }

          setChannels(prev => {
            if (prev[channel].fader === d2) return prev; // No actualizar si es el mismo
            const newChannels = [...prev];
            newChannels[channel] = { ...newChannels[channel], fader: d2 };
            return newChannels;
          });
        }
      }
      // 2. Otros mensajes (Botones, etc.)
      else if (type === 0x90 && mode === ControlMode.MCU) {
        const chIdxMute = d1 - 0x10;
        const chIdxSolo = d1 - 0x08;
        const chIdxRec = d1 - 0x00;

        if (chIdxMute >= 0 && chIdxMute < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxMute ? { ...ch, mute: d2 > 0 } : ch));
        } else if (chIdxSolo >= 0 && chIdxSolo < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxSolo ? { ...ch, solo: d2 > 0 } : ch));
        } else if (chIdxRec >= 0 && chIdxRec < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxRec ? { ...ch, rec: d2 > 0 } : ch));
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput, mode]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      sendFaderMidi(id, updates.fader);
    }
    // Botones (Solo, Mute, Rec)
    if (updates.mute !== undefined) sendMidi(0x90, 0x10 + id, updates.mute ? 127 : 0);
    if (updates.solo !== undefined) sendMidi(0x90, 0x08 + id, updates.solo ? 127 : 0);
    if (updates.rec !== undefined) sendMidi(0x90, 0x00 + id, updates.rec ? 127 : 0);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
  };

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#111] text-slate-200">
      <header className="flex items-center justify-between px-6 py-2 bg-[#222] border-b border-black shadow-lg z-10">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 bg-[#526d4f] rounded flex items-center justify-center text-white shadow-lg">
            <i className="fas fa-sliders-h"></i>
          </div>
          <h1 className="text-lg font-black tracking-tighter uppercase italic">Reaper<span className="text-[#526d4f]">Host</span></h1>
        </div>

        <div className="flex gap-4 items-end">
          <div className="flex flex-col">
            <label className="text-[8px] font-bold text-slate-500 uppercase mb-1">Midi Input</label>
            <select className="bg-black text-[10px] p-1 border border-[#333] rounded w-32" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
              <option value="">None</option>
              {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <div className="flex flex-col">
            <label className="text-[8px] font-bold text-slate-500 uppercase mb-1">Midi Output</label>
            <select className="bg-black text-[10px] p-1 border border-[#333] rounded w-32" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
              <option value="">None</option>
              {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#333] px-3 py-1.5 rounded text-[10px] font-bold hover:bg-[#444] border border-[#555]">CONFIGURAR REAPER</button>
        </div>
      </header>

      <main className="flex-grow flex p-3 gap-3 overflow-hidden">
        <div className="flex-grow flex bg-[#1a1a1a] rounded-lg border border-[#333] shadow-inner overflow-x-auto">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[90px] border-r border-black flex flex-col last:border-0">
               <div className="p-3 bg-black/40 flex flex-col items-center gap-2 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
