                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[9px] font-bold py-1 rounded border ${ch.mute ? 'bg-red-700 border-red-500 text-white' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
