                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[8px] font-bold py-1 rounded border ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse' : 'bg-zinc-900 border-zinc-700 text-red-900'}`}>REC</button>
               </div>
               <div className="flex-grow">
                 <Fader channelId={ch.id} label={ch.name} value={ch.fader} onChange={v => updateChannel(ch.id, { fader: v })} />
               </div>
            </div>
          ))}
        </div>

        <aside className="w-64 flex flex-col gap-3">
          <div className="flex-grow bg-[#222] rounded-lg border border-[#333] p-4 flex flex-col">
            <h3 className="text-[10px] font-bold text-[#526d4f] mb-2 uppercase tracking-widest">Master Meter</h3>
            <div className="flex-grow bg-black rounded border border-[#111] p-1 flex items-end gap-1">
