import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [aiHelperText, setAiHelperText] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  // Indicadores de actividad para el status bar
  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);

  // BLOQUEO CRÍTICO: Evita que la web procese mensajes de REAPER mientras el usuario mueve el fader
  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: MIDI no soportado en este navegador.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 50);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 50);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  const sendFaderMidi = useCallback((channel: number, value: number) => {
    if (lastSentValues.current[channel] === value) return;
    lastSentValues.current[channel] = value;

    if (mode === ControlMode.MCU) {
      // MCU usa Pitch Bend para faders (0xE0 + ch). 
      // Enviamos 0 como LSB y el valor (0-127) como MSB.
      sendMidi(0xE0 + channel, 0, value);
    } else {
      sendMidi(0xB0, channel, value);
    }
  }, [mode, sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) return;
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const [status, d1, d2] = event.data as any;
      const type = status & 0xf0;
      const channel = status & 0x0f;
      flashMidiIn();

      // PROTECCIÓN: Si el usuario está moviendo este fader, ignoramos lo que REAPER nos diga de este canal
      if (type === 0xE0 && mode === ControlMode.MCU) {
        if (channel < CHANNELS_COUNT && !isDragging.current[channel]) {
          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const newChannels = [...prev];
            newChannels[channel] = { ...newChannels[channel], fader: d2 };
            return newChannels;
          });
        }
      }
      else if (type === 0x90 && mode === ControlMode.MCU) {
        const chIdxMute = d1 - 0x10;
        const chIdxSolo = d1 - 0x08;
        const chIdxRec = d1 - 0x00;

        if (chIdxMute >= 0 && chIdxMute < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxMute ? { ...ch, mute: d2 > 0 } : ch));
        } else if (chIdxSolo >= 0 && chIdxSolo < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxSolo ? { ...ch, solo: d2 > 0 } : ch));
        } else if (chIdxRec >= 0 && chIdxRec < CHANNELS_COUNT) {
          setChannels(prev => prev.map((ch, i) => i === chIdxRec ? { ...ch, rec: d2 > 0 } : ch));
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput, mode]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    // Si estamos actualizando el fader, marcamos que el usuario está operando
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      sendFaderMidi(id, updates.fader);
      // Desbloqueamos después de un breve delay para permitir que REAPER tome el control otra vez
      setTimeout(() => { isDragging.current[id] = false; }, 200);
    }

    if (updates.mute !== undefined) sendMidi(0x90, 0x10 + id, updates.mute ? 127 : 0);
    if (updates.solo !== undefined) sendMidi(0x90, 0x08 + id, updates.solo ? 127 : 0);
    if (updates.rec !== undefined) sendMidi(0x90, 0x00 + id, updates.rec ? 127 : 0);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
  };

  const getInPortName = () => inputs.find(p => p.id === selectedInput)?.name || 'NONE';
  const getOutPortName = () => outputs.find(p => p.id === selectedOutput)?.name || 'NONE';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200">
      <header className="flex items-center justify-between px-6 py-2 bg-[#1a1a1a] border-b border-black shadow-xl z-10">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-[#526d4f] to-[#2a3d28] rounded-lg flex items-center justify-center text-white shadow-2xl border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-lg"></i>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <p className="text-[8px] text-[#526d4f] font-bold tracking-[0.2em] mt-1">MCU PROFESSIONAL INTERFACE</p>
          </div>
        </div>

        <div className="flex gap-4 items-center">
          <div className="flex gap-4">
            <div className="flex flex-col">
              <label className="text-[7px] font-bold text-slate-500 uppercase mb-1">Midi In</label>
              <select className="bg-black text-[10px] p-1 border border-[#333] rounded w-32 focus:border-[#526d4f] outline-none" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
                <option value="">(Disconnected)</option>
                {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="flex flex-col">
              <label className="text-[7px] font-bold text-slate-500 uppercase mb-1">Midi Out</label>
              <select className="bg-black text-[10px] p-1 border border-[#333] rounded w-32 focus:border-[#526d4f] outline-none" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
                <option value="">(Disconnected)</option>
                {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#526d4f] hover:bg-[#63825f] text-white px-4 py-2 rounded text-[10px] font-black uppercase transition-all shadow-lg border border-[#ffffff20]">Setup Guide</button>
        </div>
      </header>

      <main className="flex-grow flex p-3 gap-3 overflow-hidden bg-[#0a0a0a]">
        <div className="flex-grow flex bg-[#141414] rounded-xl border border-[#222] shadow-2xl overflow-x-auto custom-scrollbar">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[95px] border-r border-black flex flex-col last:border-0 group hover:bg-[#1a1a1a] transition-colors">
               <div className="p-3 bg-black/60 flex flex-col items-center gap-3 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
                 <div className="grid grid-cols-2 gap-1.5 w-full">
                   <button onClick={() => updateChannel(ch.id, { solo: !ch.solo })} className={`text-[10px] font-black py-1 rounded border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black shadow-lg shadow-yellow-600/20' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>S</button>
                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[10px] font-black py-1 rounded border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white shadow-lg shadow-red-700/20' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
                 </div>
                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[9px] font-black py-1.5 rounded border transition-all ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse' : 'bg-[#0a0a0a] border-zinc-800 text-red-900/60'}`}>ARM</button>
               </div>
               <div className="flex-grow">
                 <Fader channelId={ch.id} label={ch.name} value={ch.fader} onChange={v => updateChannel(ch.id, { fader: v })} />
               </div>
            </div>
          ))}
        </div>

        <aside className="w-64 flex flex-col gap-3">
          <div className="flex-grow bg-[#1a1a1a] rounded-xl border border-[#222] p-4 flex flex-col shadow-2xl">
            <h3 className="text-[10px] font-black text-[#526d4f] mb-3 uppercase tracking-widest border-b border-[#526d4f30] pb-2">Master Section</h3>
            <div className="flex-grow bg-black rounded-lg border border-[#000] p-2 flex items-end gap-1.5 relative overflow-hidden">
               {/* Grilla decorativa */}
               <div className="absolute inset-0 opacity-10 flex flex-col justify-between p-2 pointer-events-none">
                 {[...Array(10)].map((_, i) => <div key={i} className="border-t border-white w-full h-1"></div>)}
               </div>
               <div className="flex-grow bg-gradient-to-t from-green-900 via-green-500 to-red-500 rounded shadow-[0_0_15px_rgba(34,197,94,0.3)] transition-all duration-75" style={{ height: isPlaying ? '72%' : '2%' }}></div>
               <div className="flex-grow bg-gradient-to-t from-green-900 via-green-500 to-red-500 rounded shadow-[0_0_15px_rgba(34,197,94,0.3)] transition-all duration-75" style={{ height: isPlaying ? '68%' : '2%' }}></div>
            </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { setIsPlaying(true); sendMidi(0x90, 0x5E, 127); }}
            onStop={() => { setIsPlaying(false); setIsRecording(false); sendMidi(0x90, 0x5D, 127); }}
            onRec={() => { setIsRecording(!isRecording); sendMidi(0x90, 0x5F, 127); }}
            onPrev={() => sendMidi(0x90, 0x5B, 127)}
            onNext={() => sendMidi(0x90, 0x5C, 127)}
          />
        </aside>
      </main>

      {/* FOOTER / STATUS BAR MEJORADO */}
      <footer className="bg-black border-t border-[#1a1a1a] px-5 py-2 flex justify-between items-center text-[9px] font-bold tracking-widest uppercase shadow-[0_-10px_30px_rgba(0,0,0,0.5)]">
        <div className="flex gap-6 items-center">
          <div className="flex items-center gap-3">
            <span className="text-slate-500">MIDI IN:</span>
            <div className={`w-3 h-3 rounded-full border border-[#222] transition-all duration-75 ${midiInActive ? 'bg-[#526d4f] shadow-[0_0_8px_#526d4f]' : 'bg-zinc-900'}`}></div>
