          </div>
          <div className="w-[1px] h-4 bg-zinc-800"></div>
          <div className="flex items-center gap-3">
            <span className="text-slate-500">MIDI OUT:</span>
            <div className={`w-3 h-3 rounded-full border border-[#222] transition-all duration-75 ${midiOutActive ? 'bg-[#526d4f] shadow-[0_0_8px_#526d4f]' : 'bg-zinc-900'}`}></div>
            <span className="text-slate-400 font-mono text-[10px]">{getOutPortName()}</span>
          </div>
        </div>

        <div className="flex gap-6 items-center">
          <div className="flex gap-4 text-[#526d4f]">
            <span>14-BIT HIGH-RES FADERS</span>
            <span>REAPER OPTIMIZED</span>
          </div>
          <div className="px-3 py-1 bg-zinc-900 rounded text-slate-500 flex items-center gap-2">
            <i className="fas fa-check-circle text-green-800"></i>
            ENGINE: {midiAccess ? 'ACTIVE' : 'ERROR'}
          </div>
        </div>
      </footer>

      {showHelper && (
        <div className="absolute inset-0 bg-black/95 backdrop-blur-md z-50 flex items-center justify-center p-6">
          <div className="bg-[#1a1a1a] max-w-xl w-full rounded-2xl border border-[#333] shadow-2xl p-8 overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4">
              <button onClick={() => setShowHelper(false)} className="text-slate-500 hover:text-white transition-colors">
                <i className="fas fa-times text-2xl"></i>
