  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  // Estados de actividad y conexión
  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);
  const [isReaperSynced, setIsReaperSynced] = useState(false);

  // Refs para control de flujo y anti-feedback
  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const syncTimeout = useRef<any>(null);
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: MIDI no soportado.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 60);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 60);

    // Si recibimos datos, REAPER está enviando información (está "Synced")
    setIsReaperSynced(true);
    clearTimeout(syncTimeout.current);
    // Si no recibimos nada en 10 segundos, consideramos que REAPER no está respondiendo
    syncTimeout.current = setTimeout(() => setIsReaperSynced(false), 10000);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  const sendFaderMidi = useCallback((channel: number, value: number) => {
    // Solo enviamos si el valor realmente cambió
    if (lastSentValues.current[channel] === value) return;
    lastSentValues.current[channel] = value;

    if (mode === ControlMode.MCU) {
      // MCU: Pitch Bend E0-E7 para faders 1-8
      sendMidi(0xE0 + channel, 0, value);
    } else {
      sendMidi(0xB0, channel, value);
    }
  }, [mode, sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) {
        setIsReaperSynced(false);
        return;
    }
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const [status, d1, d2] = event.data as any;
      const type = status & 0xf0;
      const channel = status & 0x0f;
      flashMidiIn();

      // PROTECCIÓN ANTI-FEEDBACK REFORZADA: 
      // Si el usuario está tocando el fader físico (isDragging), bloqueamos CUALQUIER entrada de ese fader desde REAPER
      if (type === 0xE0 && mode === ControlMode.MCU) {
        if (channel < CHANNELS_COUNT) {
          if (isDragging.current[channel]) {
             // Ignoramos completamente el mensaje de REAPER mientras arrastramos
             return;
          }

          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const newChannels = [...prev];
            newChannels[channel] = { ...newChannels[channel], fader: d2 };
            return newChannels;
          });
        }
      }
      // Botones MCU
      else if (type === 0x90 && mode === ControlMode.MCU) {
        if (d1 >= 0x10 && d1 <= 0x17) { // Mutes
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
        } else if (d1 >= 0x08 && d1 <= 0x0F) { // Solos
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
        } else if (d1 >= 0x00 && d1 <= 0x07) { // Rec Arms
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x00) ? { ...ch, rec: d2 > 0 } : ch));
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput, mode]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      sendFaderMidi(id, updates.fader);

      // Debounce para liberar el fader: REAPER suele devolver el valor inmediatamente.
      // Un delay de 250ms es suficiente para que el movimiento del mouse termine y REAPER deje de enviar su eco.
      const timerId = (window as any)[`fader_timer_${id}`];
      if (timerId) clearTimeout(timerId);
      (window as any)[`fader_timer_${id}`] = setTimeout(() => {
        isDragging.current[id] = false;
      }, 250);
    }

    if (updates.mute !== undefined) sendMidi(0x90, 0x10 + id, updates.mute ? 127 : 0);
    if (updates.solo !== undefined) sendMidi(0x90, 0x08 + id, updates.solo ? 127 : 0);
    if (updates.rec !== undefined) sendMidi(0x90, 0x00 + id, updates.rec ? 127 : 0);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
  };

  const getInPortName = () => inputs.find(p => p.id === selectedInput)?.name || 'DISCONNECTED';
  const getOutPortName = () => outputs.find(p => p.id === selectedOutput)?.name || 'DISCONNECTED';

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200">
      <header className="flex items-center justify-between px-6 py-3 bg-[#181818] border-b border-black shadow-2xl z-10">
        <div className="flex items-center gap-4">
          <div className="w-11 h-11 bg-gradient-to-br from-[#526d4f] to-[#1a2b19] rounded-xl flex items-center justify-center text-white shadow-2xl border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-2 h-2 rounded-full ${isReaperSynced ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' : 'bg-zinc-800'} transition-all duration-300`}></div>
              <p className={`text-[9px] font-black tracking-widest uppercase ${isReaperSynced ? 'text-cyan-400' : 'text-zinc-600'}`}>
                {isReaperSynced ? 'DAW Link: ACTIVE' : 'DAW Link: OFFLINE'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex gap-5 items-center">
          <div className="flex gap-4">
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">Midi Input</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 focus:border-[#526d4f] outline-none transition-all" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
                <option value="">None</option>
                {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">Midi Output</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 focus:border-[#526d4f] outline-none transition-all" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
                <option value="">None</option>
                {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#222] hover:bg-[#333] text-[#526d4f] px-5 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all border border-[#333] shadow-lg">Setup Guide</button>
        </div>
      </header>

      <main className="flex-grow flex p-3 gap-3 overflow-hidden bg-[#080808]">
        <div className="flex-grow flex bg-[#121212] rounded-2xl border border-[#222] shadow-[inset_0_0_50px_rgba(0,0,0,0.5)] overflow-x-auto custom-scrollbar">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[100px] border-r border-black flex flex-col last:border-0 hover:bg-[#161616] transition-colors relative">
               <div className="p-4 bg-black/40 flex flex-col items-center gap-4 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
                 <div className="grid grid-cols-2 gap-2 w-full">
                   <button onClick={() => updateChannel(ch.id, { solo: !ch.solo })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black shadow-[0_0_15px_rgba(202,138,4,0.3)]' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>S</button>
                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white shadow-[0_0_15px_rgba(185,28,28,0.3)]' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
                 </div>
                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[10px] font-black py-2 rounded-lg border transition-all ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.4)]' : 'bg-[#0a0a0a] border-zinc-800 text-red-900/40'}`}>REC ARM</button>
               </div>
               <div className="flex-grow">
                 <Fader channelId={ch.id} label={ch.name} value={ch.fader} onChange={v => updateChannel(ch.id, { fader: v })} />
               </div>
            </div>
          ))}
        </div>

        <aside className="w-72 flex flex-col gap-3">
          <div className="flex-grow bg-[#181818] rounded-2xl border border-[#222] p-5 flex flex-col shadow-2xl relative overflow-hidden">
            <h3 className="text-[11px] font-black text-[#526d4f] mb-4 uppercase tracking-[0.2em] border-b border-[#526d4f30] pb-3 flex justify-between items-center">
              <span>Master Output</span>
              {isReaperSynced && <span className="text-cyan-500 animate-pulse text-[8px]">STREAMING</span>}
            </h3>
            <div className="flex-grow bg-black rounded-xl border border-[#000] p-3 flex items-end gap-2 relative overflow-hidden shadow-inner">
               <div className="absolute inset-0 opacity-[0.03] flex flex-col justify-between p-3 pointer-events-none">
                 {[...Array(15)].map((_, i) => <div key={i} className="border-t border-white w-full h-1"></div>)}
               </div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded shadow-[0_0_20px_rgba(82,109,79,0.2)] transition-all duration-75" style={{ height: isPlaying ? '78%' : '3%' }}></div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded shadow-[0_0_20px_rgba(82,109,79,0.2)] transition-all duration-75" style={{ height: isPlaying ? '74%' : '3%' }}></div>
            </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { setIsPlaying(true); sendMidi(0x90, 0x5E, 127); }}
            onStop={() => { setIsPlaying(false); setIsRecording(false); sendMidi(0x90, 0x5D, 127); }}
            onRec={() => { setIsRecording(!isRecording); sendMidi(0x90, 0x5F, 127); }}
            onPrev={() => sendMidi(0x90, 0x5B, 127)}
            onNext={() => sendMidi(0x90, 0x5C, 127)}
          />
        </aside>
      </main>

      {/* STATUS BAR DINÁMICO */}
      <footer className="bg-[#050505] border-t border-[#181818] px-6 py-3 flex justify-between items-center text-[10px] font-black tracking-widest uppercase shadow-[0_-15px_40px_rgba(0,0,0,0.8)] z-20">
        <div className="flex gap-8 items-center">
          <div className="flex items-center gap-4">
            <span className="text-zinc-600">INPUT:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all duration-75 ${midiInActive ? 'bg-[#526d4f] shadow-[0_0_12px_#526d4f]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono text-[11px] lowercase tracking-normal">{getInPortName()}</span>
          </div>

          <div className="w-[2px] h-5 bg-zinc-800/50"></div>

          <div className="flex items-center gap-4">
            <span className="text-zinc-600">OUTPUT:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all duration-75 ${midiOutActive ? 'bg-cyan-500 shadow-[0_0_12px_#06b6d4]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono text-[11px] lowercase tracking-normal">{getOutPortName()}</span>
          </div>

          <div className="w-[2px] h-5 bg-zinc-800/50"></div>

          <div className="flex items-center gap-3 bg-zinc-900/50 px-3 py-1.5 rounded-full border border-zinc-800/50">
             <div className={`w-2.5 h-2.5 rounded-full ${isReaperSynced ? 'bg-cyan-400 animate-pulse' : 'bg-red-900'} shadow-[0_0_10px_rgba(34,211,238,0.2)]`}></div>
             <span className={isReaperSynced ? 'text-cyan-400' : 'text-zinc-700'}>
               STATUS: {isReaperSynced ? 'REAPER CONNECTED' : 'WAITING FOR REAPER...'}
             </span>
          </div>
        </div>

        <div className="flex gap-8 items-center">
          <div className="flex gap-5 text-[#526d4f]/60 font-black">
            <span className="flex items-center gap-2"><i className="fas fa-microchip"></i> 14-BIT MCU</span>
            <span className="flex items-center gap-2"><i className="fas fa-shield-alt"></i> FEEDBACK SHIELD</span>
          </div>
          <div className={`px-4 py-2 rounded-xl flex items-center gap-3 border transition-all duration-500 ${midiAccess ? 'bg-[#526d4f10] border-[#526d4f30] text-[#526d4f]' : 'bg-red-900/10 border-red-900/30 text-red-700'}`}>
            <i className={`fas ${midiAccess ? 'fa-check-circle' : 'fa-times-circle'}`}></i>
            ENGINE: {midiAccess ? 'READY' : 'OFFLINE'}
          </div>
        </div>
      </footer>

      {showHelper && (
        <div className="absolute inset-0 bg-black/98 backdrop-blur-xl z-50 flex items-center justify-center p-6">
          <div className="bg-[#181818] max-w-2xl w-full rounded-3xl border border-[#333] shadow-[0_0_100px_rgba(0,0,0,0.9)] p-10 overflow-hidden relative">
            <button onClick={() => setShowHelper(false)} className="absolute top-8 right-8 text-zinc-500 hover:text-white transition-colors">
              <i className="fas fa-times text-3xl"></i>
            </button>

            <h2 className="text-3xl font-black text-[#526d4f] mb-8 uppercase tracking-tighter italic flex items-center gap-4">
              <i className="fas fa-plug"></i> Reaper Link Configuration
            </h2>

            <div className="space-y-6 text-base text-zinc-300 leading-relaxed">
              <div className="bg-cyan-900/10 border border-cyan-900/30 p-6 rounded-2xl">
                 <p className="text-cyan-400 font-black mb-2 flex items-center gap-2 uppercase tracking-widest text-sm">
                   <i className="fas fa-info-circle"></i> Cómo activar el estatus
                 </p>
                 <p className="text-[13px]">El indicador <b>REAPER CONNECTED</b> se activará automáticamente en cuanto esta web reciba el primer mensaje desde REAPER. Para que esto ocurra, REAPER debe estar configurado para enviar datos de vuelta.</p>
              </div>

              <div className="bg-red-900/10 border border-red-900/30 p-6 rounded-2xl">
                 <p className="text-red-500 font-black mb-2 flex items-center gap-2 uppercase tracking-widest text-sm">
                   <i className="fas fa-ban"></i> Error común de feedback
                 </p>
                 <p className="text-[13px]">Si tus faders saltan, asegúrate de haber <b>DESACTIVADO</b> los puertos en <i>MIDI Devices</i>. REAPER solo debe usarlos dentro de <i>Control/OSC/web</i>.</p>
              </div>

              <div className="space-y-4">
                <p className="font-black text-white uppercase tracking-widest text-xs">Configuración Rápida:</p>
                <div className="grid grid-cols-2 gap-4">
                  <div className="p-4 bg-black/40 rounded-xl border border-zinc-800">
                    <span className="text-[#526d4f] font-black mr-2 text-lg">1.</span>
                    <span className="text-[12px]">Preferences > Control/OSC/web.</span>
                  </div>
                  <div className="p-4 bg-black/40 rounded-xl border border-zinc-800">
                    <span className="text-[#526d4f] font-black mr-2 text-lg">2.</span>
                    <span className="text-[12px]">Elegir Mackie Control Universal.</span>
                  </div>
                </div>
              </div>
            </div>

            <button onClick={() => setShowHelper(false)} className="mt-10 w-full bg-[#526d4f] hover:bg-[#63825f] py-4 rounded-2xl font-black uppercase text-white transition-all shadow-[0_10px_30px_rgba(82,109,79,0.3)] text-sm tracking-widest">Aceptar y Conectar</button>
          </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #526d4f; }

        @keyframes pulse-soft {
          0%, 100% { opacity: 1; }
          50% { opacity: 0.6; }
        }
        .animate-pulse-soft {
          animation: pulse-soft 2s infinite ease-in-out;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [meterLevels, setMeterLevels] = useState<number[]>(new Array(CHANNELS_COUNT).fill(0));
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);
  const [isReaperSynced, setIsReaperSynced] = useState(false);

  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const syncTimeout = useRef<any>(null);
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess().then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('MIDI no soportado.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 50);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 50);
    setIsReaperSynced(true);
    clearTimeout(syncTimeout.current);
    syncTimeout.current = setTimeout(() => setIsReaperSynced(false), 5000);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  // Función para simular presión física de botón (Note On 127 -> Note On 0)
  const sendMomentaryButton = useCallback((note: number) => {
    sendMidi(0x90, note, 127); // Press
    setTimeout(() => sendMidi(0x90, note, 0), 50); // Release
  }, [sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) {
        setIsReaperSynced(false);
        return;
    }
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const data = event.data;
      if (!data || data.length < 2) return;

      const status = data[0];
      const d1 = data[1];
      const d2 = data.length > 2 ? data[2] : 0;

      const type = status & 0xf0;
      const channel = status & 0x0f;
      flashMidiIn();

      // 1. VU METERS (MCU usa Channel Pressure 0xD0 - 0xD7 para niveles de canal)
      if (type === 0xD0) {
        const ch = channel;
        if (ch < CHANNELS_COUNT) {
          setMeterLevels(prev => {
            const next = [...prev];
            next[ch] = d1; // En MCU, d1 suele ser el valor del medidor
            return next;
          });
        }
        return;
      }

      // 2. FADERS (Pitch Bend)
      if (type === 0xE0 && mode === ControlMode.MCU) {
        if (channel < CHANNELS_COUNT && !isDragging.current[channel]) {
          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const newChannels = [...prev];
            newChannels[channel] = { ...newChannels[channel], fader: d2 };
            return newChannels;
          });
        }
      }

      // 3. BOTONES (Note On)
      else if (type === 0x90 && mode === ControlMode.MCU) {
        // Ignoramos mensajes con d1 = 0 si es una nota fantasma
        if (status === 0x90) {
           if (d1 >= 0x10 && d1 <= 0x17) { // Mute
             setChannels(prev => prev.map((ch, i) => i === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
           } else if (d1 >= 0x08 && d1 <= 0x0F) { // Solo
             setChannels(prev => prev.map((ch, i) => i === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
           } else if (d1 >= 0x00 && d1 <= 0x07) { // Rec Arm
             setChannels(prev => prev.map((ch, i) => i === (d1 - 0x00) ? { ...ch, rec: d2 > 0 } : ch));
           }
        }
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput, mode]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      if (lastSentValues.current[id] !== updates.fader) {
        lastSentValues.current[id] = updates.fader;
        sendMidi(0xE0 + id, 0, updates.fader);
      }
      const timerId = (window as any)[`fader_timer_${id}`];
      if (timerId) clearTimeout(timerId);
      (window as any)[`fader_timer_${id}`] = setTimeout(() => { isDragging.current[id] = false; }, 200);
    }

    // Para botones, NO actualizamos el estado local. Enviamos el mensaje a REAPER y esperamos que REAPER nos devuelva el estado.
    // Esto soluciona el problema de tener que apretar dos veces.
    if (updates.mute !== undefined) sendMomentaryButton(0x10 + id);
    if (updates.solo !== undefined) sendMomentaryButton(0x08 + id);
    if (updates.rec !== undefined) sendMomentaryButton(0x00 + id);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    // Solo actualizamos localmente lo que no sea toggle de REAPER (como fader o pan mientras arrastramos)
    if (updates.fader !== undefined || updates.pan !== undefined) {
        setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
    }
  };

  const getInPortName = () => inputs.find(p => p.id === selectedInput)?.name || 'NONE';
  const getOutPortName = () => outputs.find(p => p.id === selectedOutput)?.name || 'NONE';

  // Calculamos el nivel promedio para el master dinámico
  const masterLevel = meterLevels.reduce((a, b) => a + b, 0) / CHANNELS_COUNT;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200 font-sans">
      <header className="flex items-center justify-between px-6 py-3 bg-[#181818] border-b border-black shadow-2xl z-10">
        <div className="flex items-center gap-4">
          <div className="w-11 h-11 bg-gradient-to-br from-[#526d4f] to-[#1a2b19] rounded-xl flex items-center justify-center text-white shadow-2xl border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-2 h-2 rounded-full ${isReaperSynced ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' : 'bg-zinc-800'} transition-all duration-300`}></div>
              <p className={`text-[9px] font-black tracking-widest uppercase ${isReaperSynced ? 'text-cyan-400' : 'text-zinc-600'}`}>
                {isReaperSynced ? 'LINKED TO REAPER' : 'DAW LINK OFFLINE'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex gap-5 items-center">
          <div className="flex gap-4">
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">In</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
                <option value="">(None)</option>
                {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">Out</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
                <option value="">(None)</option>
                {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#222] hover:bg-[#333] text-[#526d4f] px-5 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all border border-[#333]">Setup Guide</button>
        </div>
