import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [meterLevels, setMeterLevels] = useState<number[]>(new Array(CHANNELS_COUNT).fill(0));
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);
  const [isReaperSynced, setIsReaperSynced] = useState(false);

  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const syncTimeout = useRef<any>(null);
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      // Pedimos acceso incluyendo SysEx para poder recibir nombres de pistas
      navigator.requestMIDIAccess({ sysex: true }).then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: No se pudo obtener acceso MIDI con soporte SysEx.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 50);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 50);
    setIsReaperSynced(true);
    clearTimeout(syncTimeout.current);
    syncTimeout.current = setTimeout(() => setIsReaperSynced(false), 5000);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  const sendMomentaryButton = useCallback((note: number) => {
    sendMidi(0x90, note, 127); // Press
    setTimeout(() => sendMidi(0x90, note, 0), 50); // Release
  }, [sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) {
        setIsReaperSynced(false);
        return;
    }
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const data = event.data;
      if (!data || data.length < 2) return;

      const status = data[0];
      flashMidiIn();

      // --- MANEJO DE SYSEX PARA NOMBRES DE PISTAS (LCD Display MCU) ---
      // Formato MCU LCD: F0 00 00 66 14 12 offset data... F7
      if (status === 0xF0 && data.length > 7) {
        if (data[1] === 0x00 && data[2] === 0x00 && data[3] === 0x66 && data[5] === 0x12) {
          const offset = data[6];
          const textData = data.slice(7, data.length - 1);
          const text = String.fromCharCode(...Array.from(textData));

          setChannels(prev => {
            const next = [...prev];
            // En MCU, el LCD tiene 56 caracteres por fila. 
            // Cada canal suele ocupar 7 caracteres (8 canales * 7 = 56)
            for (let i = 0; i < CHANNELS_COUNT; i++) {
              const start = i * 7;
              // Si el mensaje SysEx intersecta con el espacio de este canal:
              if (offset <= start + 6 && offset + text.length > start) {
                const charStartInText = Math.max(0, start - offset);
                const charEndInText = Math.min(text.length, start + 7 - offset);
                const channelPart = text.substring(charStartInText, charEndInText).trim();

                if (channelPart && channelPart !== next[i].name) {
                  // Solo actualizamos si el nombre parece válido y diferente
                  next[i] = { ...next[i], name: channelPart || `CH ${i+1}` };
                }
              }
            }
            return next;
          });
        }
        return;
      }

      const d1 = data[1];
      const d2 = data.length > 2 ? data[2] : 0;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      // VU Meters (MCU Channel Pressure)
      if (type === 0xD0) {
        if (channel < CHANNELS_COUNT) {
          setMeterLevels(prev => {
            const next = [...prev];
            next[channel] = d1;
            return next;
          });
        }
        return;
      }

      // Faders (Pitch Bend)
      if (type === 0xE0) {
        if (channel < CHANNELS_COUNT && !isDragging.current[channel]) {
          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const next = [...prev];
            next[channel] = { ...next[channel], fader: d2 };
            return next;
          });
        }
      }

      // Botones MCU (Note On)
      else if (type === 0x90) {
        if (d1 >= 0x10 && d1 <= 0x17) { // Mute
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
        } else if (d1 >= 0x08 && d1 <= 0x0F) { // Solo
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
        } else if (d1 >= 0x00 && d1 <= 0x07) { // Rec Arm
          setChannels(prev => prev.map((ch, i) => i === (d1 - 0x00) ? { ...ch, rec: d2 > 0 } : ch));
        }
        // Transport Sync (Opcional si REAPER envía Note On para Play/Stop)
        if (d1 === 0x5E) setIsPlaying(d2 > 0);
        if (d1 === 0x5F) setIsRecording(d2 > 0);
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      if (lastSentValues.current[id] !== updates.fader) {
        lastSentValues.current[id] = updates.fader;
        sendMidi(0xE0 + id, 0, updates.fader);
      }
      const timerId = (window as any)[`fader_timer_${id}`];
      if (timerId) clearTimeout(timerId);
      (window as any)[`fader_timer_${id}`] = setTimeout(() => { isDragging.current[id] = false; }, 200);
    }

    if (updates.mute !== undefined) sendMomentaryButton(0x10 + id);
    if (updates.solo !== undefined) sendMomentaryButton(0x08 + id);
    if (updates.rec !== undefined) sendMomentaryButton(0x00 + id);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    if (updates.fader !== undefined || updates.pan !== undefined) {
        setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
    }
  };

  // Helper function to get the name of the selected MIDI input port
  const getInPortName = () => {
    const port = inputs.find(p => p.id === selectedInput);
    return port ? port.name : 'disconnected';
  };

  // Helper function to get the name of the selected MIDI output port
  const getOutPortName = () => {
    const port = outputs.find(p => p.id === selectedOutput);
    return port ? port.name : 'disconnected';
  };

  const masterLevel = meterLevels.reduce((a, b) => a + b, 0) / CHANNELS_COUNT;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200 font-sans">
      <header className="flex items-center justify-between px-6 py-3 bg-[#181818] border-b border-black shadow-2xl z-10">
        <div className="flex items-center gap-4">
          <div className="w-11 h-11 bg-gradient-to-br from-[#526d4f] to-[#1a2b19] rounded-xl flex items-center justify-center text-white shadow-2xl border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-2 h-2 rounded-full ${isReaperSynced ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' : 'bg-zinc-800'} transition-all duration-300`}></div>
              <p className={`text-[9px] font-black tracking-widest uppercase ${isReaperSynced ? 'text-cyan-400' : 'text-zinc-600'}`}>
                {isReaperSynced ? 'DYNAMIC TRACK LINK ACTIVE' : 'DAW LINK OFFLINE'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex gap-5 items-center">
          <div className="flex gap-4">
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">In</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
                <option value="">(None)</option>
                {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-slate-500 uppercase mb-1">Out</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
                <option value="">(None)</option>
                {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#222] hover:bg-[#333] text-[#526d4f] px-5 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all border border-[#333]">Setup Guide</button>
        </div>
      </header>

      <main className="flex-grow flex p-3 gap-3 overflow-hidden bg-[#080808]">
        <div className="flex-grow flex bg-[#121212] rounded-2xl border border-[#222] shadow-[inset_0_0_50px_rgba(0,0,0,0.5)] overflow-x-auto custom-scrollbar">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[110px] border-r border-black flex flex-col last:border-0 hover:bg-[#161616] transition-colors relative">
               <div className="p-4 bg-black/40 flex flex-col items-center gap-4 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
                 <div className="grid grid-cols-2 gap-2 w-full">
                   <button onClick={() => updateChannel(ch.id, { solo: !ch.solo })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black shadow-[0_0_15px_rgba(202,138,4,0.3)]' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>S</button>
                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white shadow-[0_0_15px_rgba(185,28,28,0.3)]' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
                 </div>
                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[10px] font-black py-2 rounded-lg border transition-all ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse shadow-[0_0_15px_rgba(220,38,38,0.4)]' : 'bg-[#0a0a0a] border-zinc-800 text-red-900/40'}`}>REC</button>
