              <span>Master VU</span>
              {isReaperSynced && <span className="text-cyan-500 animate-pulse text-[8px]">LIVE SYNC</span>}
            </h3>
            <div className="flex-grow bg-black rounded-xl border border-[#000] p-3 flex items-end gap-2 relative overflow-hidden shadow-inner">
               <div className="absolute inset-0 opacity-[0.03] flex flex-col justify-between p-3 pointer-events-none">
                 {[...Array(15)].map((_, i) => <div key={i} className="border-t border-white w-full h-1"></div>)}
               </div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded shadow-[0_0_20px_rgba(82,109,79,0.2)]" style={{ height: `${Math.max(1, (masterLevel / 127) * 98)}%`, transition: 'height 0.05s' }}></div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded shadow-[0_0_20px_rgba(82,109,79,0.2)]" style={{ height: `${Math.max(1, (masterLevel / 127) * 94)}%`, transition: 'height 0.05s' }}></div>
            </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { setIsPlaying(true); sendMomentaryButton(0x5E); }}
            onStop={() => { setIsPlaying(false); setIsRecording(false); sendMomentaryButton(0x5D); }}
            onRec={() => { setIsRecording(!isRecording); sendMomentaryButton(0x5F); }}
            onPrev={() => sendMomentaryButton(0x5B)}
            onNext={() => sendMomentaryButton(0x5C)}
          />
        </aside>
      </main>

      <footer className="bg-[#050505] border-t border-[#181818] px-6 py-3 flex justify-between items-center text-[10px] font-black uppercase z-20">
        <div className="flex gap-8 items-center">
          <div className="flex items-center gap-4">
            <span className="text-zinc-600">MIDI IN:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all ${midiInActive ? 'bg-[#526d4f] shadow-[0_0_12px_#526d4f]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono lowercase tracking-normal">{getInPortName()}</span>
          </div>
          <div className="w-[2px] h-5 bg-zinc-800/50"></div>
          <div className="flex items-center gap-4">
            <span className="text-zinc-600">MIDI OUT:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all ${midiOutActive ? 'bg-cyan-500 shadow-[0_0_12px_#06b6d4]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono lowercase tracking-normal">{getOutPortName()}</span>
          </div>
          <div className="w-[2px] h-5 bg-zinc-800/50"></div>
          <div className="flex items-center gap-3 bg-zinc-900/50 px-3 py-1.5 rounded-full border border-zinc-800/50">
             <div className={`w-2.5 h-2.5 rounded-full ${isReaperSynced ? 'bg-cyan-400 shadow-[0_0_10px_rgba(34,211,238,0.5)]' : 'bg-red-900'}`}></div>
             <span className={isReaperSynced ? 'text-cyan-400' : 'text-zinc-700'}>
               STATUS: {isReaperSynced ? 'DAW SYNCED' : 'AWAITING REAPER'}
             </span>
          </div>
        </div>
        <div className="flex gap-8 items-center text-[#526d4f]/60">
           <span>SYSEX NAME ENGINE ENABLED</span>
           <span className={`flex items-center gap-2 ${midiAccess ? 'text-green-800' : 'text-red-900'}`}>
              <i className="fas fa-plug"></i> {midiAccess ? 'SYSEX OK' : 'SYSEX ERROR'}
           </span>
        </div>
      </footer>

      {showHelper && (
        <div className="absolute inset-0 bg-black/98 backdrop-blur-xl z-50 flex items-center justify-center p-6">
          <div className="bg-[#181818] max-w-2xl w-full rounded-3xl border border-[#333] shadow-[0_0_100px_rgba(0,0,0,0.9)] p-10 relative">
            <button onClick={() => setShowHelper(false)} className="absolute top-8 right-8 text-zinc-500 hover:text-white"><i className="fas fa-times text-3xl"></i></button>
            <h2 className="text-3xl font-black text-[#526d4f] mb-8 uppercase italic flex items-center gap-4"><i className="fas fa-plug"></i> Track Names & Setup</h2>
            <div className="space-y-6 text-zinc-300">
              <div className="bg-cyan-900/10 border border-cyan-900/30 p-6 rounded-2xl">
                 <p className="text-cyan-400 font-black mb-2 uppercase tracking-widest text-sm italic">NOMBRES DE PISTAS REALES</p>
                 <p className="text-[13px]">Esta app ahora escucha mensajes SysEx de Mackie Control. REAPER enviará automáticamente los nombres de tus pistas (Track 1, Guitarras, Voces, etc.) y se mostrarán en cada fader.</p>
              </div>
              <div className="bg-green-900/10 border border-green-900/30 p-6 rounded-2xl">
                 <p className="text-green-400 font-black mb-2 uppercase tracking-widest text-sm italic">¿QUÉ HACER EN REAPER?</p>
                 <p className="text-[13px]">Asegúrate de que en <i>Control/OSC/web</i>, al configurar Mackie Control Universal, el puerto MIDI Output de REAPER esté conectado al puerto MIDI Input de esta web.</p>
              </div>
            </div>
            <button onClick={() => setShowHelper(false)} className="mt-10 w-full bg-[#526d4f] hover:bg-[#63825f] py-4 rounded-2xl font-black uppercase text-white shadow-xl">Entendido</button>
          </div>
        </div>
      )}
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; border-radius: 10px; } .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #526d4f; }`}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [meterLevels, setMeterLevels] = useState<number[]>(new Array(CHANNELS_COUNT).fill(0));
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  // IA Support States
  const [aiResponse, setAiResponse] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);
  const [isReaperSynced, setIsReaperSynced] = useState(false);

  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const syncTimeout = useRef<any>(null);
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess({ sysex: true }).then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: MIDI no disponible.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 50);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 50);
    setIsReaperSynced(true);
    clearTimeout(syncTimeout.current);
    syncTimeout.current = setTimeout(() => setIsReaperSynced(false), 5000);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  const sendMomentaryButton = useCallback((note: number) => {
    sendMidi(0x90, note, 127); // Press
    setTimeout(() => sendMidi(0x90, note, 0), 50); // Release
  }, [sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) {
        setIsReaperSynced(false);
        return;
    }
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const data = event.data;
      if (!data || data.length < 2) return;
      const status = data[0];
      flashMidiIn();

      // LCD Names (SysEx)
      if (status === 0xF0 && data.length > 7) {
        if (data[1] === 0x00 && data[2] === 0x00 && data[3] === 0x66 && data[5] === 0x12) {
          const offset = data[6];
          const text = String.fromCharCode(...Array.from(data.slice(7, data.length - 1)));
          setChannels(prev => {
            const next = [...prev];
            for (let i = 0; i < CHANNELS_COUNT; i++) {
              const start = i * 7;
              if (offset <= start + 6 && offset + text.length > start) {
                const charStart = Math.max(0, start - offset);
                const charEnd = Math.min(text.length, start + 7 - offset);
                const part = text.substring(charStart, charEnd).trim();
                if (part && part !== next[i].name) next[i] = { ...next[i], name: part };
              }
            }
            return next;
          });
        }
        return;
      }

      const d1 = data[1];
      const d2 = data.length > 2 ? data[2] : 0;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      // VU Meters (D0-D7 Channel Pressure)
      if (type === 0xD0) {
        if (channel < CHANNELS_COUNT) {
          setMeterLevels(prev => {
            const next = [...prev];
            next[channel] = d1;
            return next;
          });
        }
        return;
      }

      // Faders (E0-E7 Pitch Bend)
      if (type === 0xE0) {
        if (channel < CHANNELS_COUNT && !isDragging.current[channel]) {
          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const next = [...prev];
            next[channel] = { ...next[channel], fader: d2 };
            return next;
          });
        }
      }

      // Buttons (90 Note On)
      else if (type === 0x90) {
        if (d1 >= 0x10 && d1 <= 0x17) setChannels(p => p.map((ch, i) => i === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
        if (d1 >= 0x08 && d1 <= 0x0F) setChannels(p => p.map((ch, i) => i === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
        if (d1 >= 0x00 && d1 <= 0x07) setChannels(p => p.map((ch, i) => i === (d1 - 0x00) ? { ...ch, rec: d2 > 0 } : ch));
        if (d1 === 0x5E) setIsPlaying(d2 > 0);
        if (d1 === 0x5F) setIsRecording(d2 > 0);
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      if (lastSentValues.current[id] !== updates.fader) {
        lastSentValues.current[id] = updates.fader;
        sendMidi(0xE0 + id, 0, updates.fader);
      }
      const timerId = (window as any)[`fader_timer_${id}`];
      if (timerId) clearTimeout(timerId);
      (window as any)[`fader_timer_${id}`] = setTimeout(() => { isDragging.current[id] = false; }, 200);
    }

    if (updates.mute !== undefined) sendMomentaryButton(0x10 + id);
    if (updates.solo !== undefined) sendMomentaryButton(0x08 + id);
    if (updates.rec !== undefined) sendMomentaryButton(0x00 + id);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    if (updates.fader !== undefined || updates.pan !== undefined) {
        setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
    }
  };

  const handleAiHelp = async () => {
    setIsAiLoading(true);
    const inPort = inputs.find(p => p.id === selectedInput)?.name || 'None';
    const outPort = outputs.find(p => p.id === selectedOutput)?.name || 'None';
    const query = `Setting up with In: ${inPort}, Out: ${outPort}. How do I fix connection issues?`;
    const help = await getMidiAssistance(query, mode);
    setAiResponse(help);
    setIsAiLoading(false);
  };

  const getInPortName = () => inputs.find(p => p.id === selectedInput)?.name || 'disconnected';
  const getOutPortName = () => outputs.find(p => p.id === selectedOutput)?.name || 'disconnected';
  const masterLevel = meterLevels.reduce((a, b) => a + b, 0) / CHANNELS_COUNT;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200 font-sans">
      <header className="flex items-center justify-between px-6 py-3 bg-[#181818] border-b border-black shadow-2xl z-10">
        <div className="flex items-center gap-4">
          <div className="w-11 h-11 bg-gradient-to-br from-[#526d4f] to-[#1a2b19] rounded-xl flex items-center justify-center text-white shadow-2xl border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-2 h-2 rounded-full ${isReaperSynced ? 'bg-cyan-400 shadow-[0_0_8px_cyan]' : 'bg-zinc-800'} transition-all duration-300`}></div>
              <p className={`text-[9px] font-black tracking-widest uppercase ${isReaperSynced ? 'text-cyan-400' : 'text-zinc-600'}`}>
                {isReaperSynced ? 'SYSTEM ONLINE' : 'OFFLINE'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex gap-5 items-center">
          <div className="flex gap-4">
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-zinc-500 uppercase mb-1">MIDI Input</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none hover:border-[#526d4f] transition-all" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
                <option value="">(None)</option>
                {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
            <div className="flex flex-col">
              <label className="text-[8px] font-black text-zinc-500 uppercase mb-1">MIDI Output</label>
              <select className="bg-black text-[11px] p-2 border border-[#333] rounded-lg w-40 outline-none hover:border-[#526d4f] transition-all" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
                <option value="">(None)</option>
                {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
              </select>
            </div>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#222] hover:bg-[#333] text-[#526d4f] px-5 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all border border-[#333] flex items-center gap-2">
            <i className="fas fa-magic text-[10px]"></i> AI Setup Assistant
          </button>
        </div>
      </header>

      <main className="flex-grow flex p-3 gap-3 overflow-hidden bg-[#080808]">
        <div className="flex-grow flex bg-[#121212] rounded-2xl border border-[#222] shadow-[inset_0_0_50px_rgba(0,0,0,0.5)] overflow-x-auto custom-scrollbar">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[110px] border-r border-black flex flex-col last:border-0 hover:bg-[#161616] transition-colors relative">
               <div className="p-4 bg-black/40 flex flex-col items-center gap-4 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
                 <div className="grid grid-cols-2 gap-2 w-full">
                   <button onClick={() => updateChannel(ch.id, { solo: !ch.solo })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black shadow-lg shadow-yellow-600/20' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>S</button>
                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[11px] font-black py-1.5 rounded-lg border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white shadow-lg shadow-red-700/20' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
                 </div>
                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[10px] font-black py-2 rounded-lg border transition-all ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse' : 'bg-[#0a0a0a] border-zinc-800 text-red-900/40'}`}>REC</button>
               </div>
               <div className="flex-grow relative flex">
                 <Fader channelId={ch.id} label={ch.name} value={ch.fader} onChange={v => updateChannel(ch.id, { fader: v })} />
                 <div className="w-1.5 bg-black absolute right-2 top-10 bottom-10 rounded-full overflow-hidden flex flex-col justify-end">
                    <div className="bg-gradient-to-t from-green-500 via-yellow-500 to-red-500 w-full shadow-[0_0_10px_rgba(34,197,94,0.3)] transition-all duration-75" style={{ height: `${(meterLevels[ch.id] / 127) * 100}%` }}></div>
                 </div>
               </div>
            </div>
          ))}
        </div>

        <aside className="w-72 flex flex-col gap-3">
          <div className="flex-grow bg-[#181818] rounded-2xl border border-[#222] p-5 flex flex-col shadow-2xl relative overflow-hidden">
            <h3 className="text-[11px] font-black text-[#526d4f] mb-4 uppercase tracking-[0.2em] border-b border-[#526d4f30] pb-3 flex justify-between items-center">
              <span>Master VU</span>
              {isReaperSynced && <i className="fas fa-link text-cyan-500 animate-pulse text-[10px]"></i>}
            </h3>
            <div className="flex-grow bg-black rounded-xl border border-[#000] p-4 flex items-end gap-2.5 relative overflow-hidden shadow-inner">
               <div className="absolute inset-0 opacity-[0.03] flex flex-col justify-between p-4 pointer-events-none">
                 {[...Array(15)].map((_, i) => <div key={i} className="border-t border-white w-full h-1"></div>)}
               </div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded-sm shadow-[0_0_20px_rgba(82,109,79,0.15)] transition-all duration-100" style={{ height: `${Math.max(2, (masterLevel / 127) * 98)}%` }}></div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded-sm shadow-[0_0_20px_rgba(82,109,79,0.15)] transition-all duration-100" style={{ height: `${Math.max(2, (masterLevel / 127) * 94)}%` }}></div>
            </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { setIsPlaying(true); sendMomentaryButton(0x5E); }}
            onStop={() => { setIsPlaying(false); setIsRecording(false); sendMomentaryButton(0x5D); }}
            onRec={() => { setIsRecording(!isRecording); sendMomentaryButton(0x5F); }}
            onPrev={() => sendMomentaryButton(0x5B)}
            onNext={() => sendMomentaryButton(0x5C)}
          />
        </aside>
      </main>

      <footer className="bg-[#050505] border-t border-[#181818] px-6 py-3 flex justify-between items-center text-[10px] font-black uppercase z-20">
        <div className="flex gap-8 items-center">
          <div className="flex items-center gap-4">
            <span className="text-zinc-600">IN:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all ${midiInActive ? 'bg-[#526d4f] shadow-[0_0_12px_#526d4f]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono tracking-tight lowercase">{getInPortName()}</span>
          </div>
          <div className="w-[1px] h-4 bg-zinc-800"></div>
          <div className="flex items-center gap-4">
            <span className="text-zinc-600">OUT:</span>
            <div className={`w-3.5 h-3.5 rounded-full border border-black transition-all ${midiOutActive ? 'bg-cyan-500 shadow-[0_0_12px_#06b6d4]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-400 font-mono tracking-tight lowercase">{getOutPortName()}</span>
          </div>
          <div className="w-[1px] h-4 bg-zinc-800"></div>
          <div className="flex items-center gap-3 bg-zinc-900/40 px-3 py-1.5 rounded-full border border-zinc-800/40">
             <div className={`w-2 h-2 rounded-full ${isReaperSynced ? 'bg-cyan-400 animate-pulse shadow-[0_0_10px_cyan]' : 'bg-red-900'}`}></div>
             <span className={isReaperSynced ? 'text-cyan-400' : 'text-zinc-700'}>
               {isReaperSynced ? 'DAW CONNECTED' : 'DAW LINK WAITING'}
             </span>
          </div>
        </div>
        <div className="flex gap-8 items-center">
           <span className="text-zinc-700 flex items-center gap-2"><i className="fas fa-brain text-[#526d4f]"></i> GEMINI AI READY</span>
           <div className={`px-4 py-1.5 rounded-full flex items-center gap-3 border ${midiAccess ? 'bg-[#526d4f10] border-[#526d4f30] text-[#526d4f]' : 'bg-red-900/10 border-red-900/30 text-red-700'}`}>
              <i className={`fas ${midiAccess ? 'fa-check-circle' : 'fa-times-circle'}`}></i>
              {midiAccess ? 'MIDI DRIVER OK' : 'DRIVER ERROR'}
           </div>
        </div>
      </footer>

      {showHelper && (
        <div className="absolute inset-0 bg-black/98 backdrop-blur-2xl z-50 flex items-center justify-center p-6">
          <div className="bg-[#181818] max-w-3xl w-full rounded-3xl border border-[#333] shadow-[0_0_150px_rgba(0,0,0,1)] p-10 relative overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-[#526d4f] opacity-5 blur-[120px] rounded-full -mr-32 -mt-32"></div>
            <button onClick={() => setShowHelper(false)} className="absolute top-8 right-8 text-zinc-500 hover:text-white transition-all"><i className="fas fa-times text-3xl"></i></button>

            <h2 className="text-3xl font-black text-[#526d4f] mb-8 uppercase italic flex items-center gap-4"><i className="fas fa-robot"></i> Smart Setup Assistant</h2>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
              <div className="space-y-6 text-zinc-300">
                <div className="bg-zinc-900/60 p-6 rounded-2xl border border-zinc-800">
                  <p className="text-white font-black mb-3 text-sm uppercase italic">Quick Setup</p>
                  <ul className="space-y-3 text-[13px] text-zinc-400">
                    <li className="flex items-center gap-3"><span className="w-5 h-5 bg-[#526d4f] text-white rounded flex items-center justify-center text-[10px] font-black">1</span> In DAW, Add Mackie Control</li>
                    <li className="flex items-center gap-3"><span className="w-5 h-5 bg-[#526d4f] text-white rounded flex items-center justify-center text-[10px] font-black">2</span> Link MIDI Input to Virtual Out</li>
                    <li className="flex items-center gap-3"><span className="w-5 h-5 bg-[#526d4f] text-white rounded flex items-center justify-center text-[10px] font-black">3</span> Link MIDI Output to Virtual In</li>
                  </ul>
                </div>
                <button 
                  onClick={handleAiHelp} 
                  disabled={isAiLoading}
                  className="w-full bg-[#526d4f] hover:bg-[#63825f] py-4 rounded-2xl font-black uppercase text-white shadow-[0_10px_30px_rgba(82,109,79,0.3)] flex items-center justify-center gap-3 transition-all disabled:opacity-50"
                >
                  {isAiLoading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-sparkles"></i>}
                  {isAiLoading ? 'Analyzing System...' : 'Generate AI Diagnostics'}
                </button>
              </div>

              <div className="bg-black rounded-2xl border border-zinc-800 p-6 h-[300px] overflow-y-auto custom-scrollbar">
                <p className="text-[10px] font-black text-zinc-500 mb-4 uppercase tracking-widest border-b border-zinc-800 pb-2 flex items-center gap-2">
                  <i className="fas fa-terminal"></i> Gemini Output
                </p>
                {aiResponse ? (
                  <div className="text-[13px] text-zinc-300 leading-relaxed space-y-4">
                    {aiResponse.split('\n').map((line, i) => <p key={i}>{line}</p>)}
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center text-center text-zinc-600 space-y-3">
                    <i className="fas fa-comment-dots text-3xl opacity-20"></i>
                    <p className="text-[11px] font-bold">Haz clic en "Generate AI Diagnostics" para recibir asistencia personalizada basada en tu hardware.</p>
                  </div>
                )}
              </div>
            </div>

            <button onClick={() => setShowHelper(false)} className="w-full border border-zinc-700 hover:bg-zinc-800 py-3 rounded-2xl font-black uppercase text-zinc-400 transition-all">Close</button>
          </div>
        </div>
      )}
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 6px; height: 6px; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #222; border-radius: 10px; } .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #526d4f; }`}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { ControlMode, MidiPort, ChannelData } from './types';
import Fader from './components/Fader';
import Knob from './components/Knob';
import Transport from './components/Transport';
import { getMidiAssistance } from './services/geminiService';

const CHANNELS_COUNT = 8;

const INITIAL_CHANNELS: ChannelData[] = Array.from({ length: CHANNELS_COUNT }, (_, i) => ({
  id: i,
  name: `Track ${i + 1}`,
  fader: 0,
  pan: 64,
  mute: false,
  solo: false,
  rec: false
}));

const App: React.FC = () => {
  const [midiAccess, setMidiAccess] = useState<MIDIAccess | null>(null);
  const [inputs, setInputs] = useState<MidiPort[]>([]);
  const [outputs, setOutputs] = useState<MidiPort[]>([]);
  const [selectedInput, setSelectedInput] = useState<string>('');
  const [selectedOutput, setSelectedOutput] = useState<string>('');
  const [channels, setChannels] = useState<ChannelData[]>(INITIAL_CHANNELS);
  const [meterLevels, setMeterLevels] = useState<number[]>(new Array(CHANNELS_COUNT).fill(0));
  const [mode, setMode] = useState<ControlMode>(ControlMode.MCU);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [showHelper, setShowHelper] = useState(false);

  const [aiResponse, setAiResponse] = useState<string>('');
  const [isAiLoading, setIsAiLoading] = useState(false);

  const [midiInActive, setMidiInActive] = useState(false);
  const [midiOutActive, setMidiOutActive] = useState(false);
  const [isReaperSynced, setIsReaperSynced] = useState(false);

  const isDragging = useRef<boolean[]>(new Array(CHANNELS_COUNT).fill(false));
  const lastSentValues = useRef<number[]>(new Array(CHANNELS_COUNT).fill(-1));
  const syncTimeout = useRef<any>(null);
  const activityTimeoutIn = useRef<any>(null);
  const activityTimeoutOut = useRef<any>(null);

  useEffect(() => {
    if (navigator.requestMIDIAccess) {
      navigator.requestMIDIAccess({ sysex: true }).then(
        (access) => {
          setMidiAccess(access);
          updatePorts(access);
          access.onstatechange = () => updatePorts(access);
        },
        () => alert('Error: MIDI no disponible.')
      );
    }
  }, []);

  const updatePorts = (access: MIDIAccess) => {
    const inputPorts: MidiPort[] = [];
    const outputPorts: MidiPort[] = [];
    access.inputs.forEach((p) => inputPorts.push({ id: p.id, name: p.name || 'In', manufacturer: '' }));
    access.outputs.forEach((p) => outputPorts.push({ id: p.id, name: p.name || 'Out', manufacturer: '' }));
    setInputs(inputPorts);
    setOutputs(outputPorts);
  };

  const flashMidiOut = () => {
    setMidiOutActive(true);
    clearTimeout(activityTimeoutOut.current);
    activityTimeoutOut.current = setTimeout(() => setMidiOutActive(false), 50);
  };

  const flashMidiIn = () => {
    setMidiInActive(true);
    clearTimeout(activityTimeoutIn.current);
    activityTimeoutIn.current = setTimeout(() => setMidiInActive(false), 50);
    setIsReaperSynced(true);
    clearTimeout(syncTimeout.current);
    syncTimeout.current = setTimeout(() => setIsReaperSynced(false), 5000);
  };

  const sendMidi = useCallback((status: number, d1: number, d2: number) => {
    if (!midiAccess || !selectedOutput) return;
    const output = midiAccess.outputs.get(selectedOutput);
    if (output) {
      output.send([status, d1, d2]);
      flashMidiOut();
    }
  }, [midiAccess, selectedOutput]);

  const sendMomentaryButton = useCallback((note: number) => {
    sendMidi(0x90, note, 127); // Press
    setTimeout(() => sendMidi(0x90, note, 0), 50); // Release
  }, [sendMidi]);

  useEffect(() => {
    if (!midiAccess || !selectedInput) {
        setIsReaperSynced(false);
        return;
    }
    const input = midiAccess.inputs.get(selectedInput);
    if (!input) return;

    const onMessage = (event: MIDIMessageEvent) => {
      const data = event.data;
      if (!data || data.length < 2) return;
      const status = data[0];
      flashMidiIn();

      if (status === 0xF0 && data.length > 7) {
        if (data[1] === 0x00 && data[2] === 0x00 && data[3] === 0x66 && data[5] === 0x12) {
          const offset = data[6];
          const text = String.fromCharCode(...Array.from(data.slice(7, data.length - 1)));
          setChannels(prev => {
            const next = [...prev];
            for (let i = 0; i < CHANNELS_COUNT; i++) {
              const start = i * 7;
              if (offset <= start + 6 && offset + text.length > start) {
                const charStart = Math.max(0, start - offset);
                const charEnd = Math.min(text.length, start + 7 - offset);
                const part = text.substring(charStart, charEnd).trim();
                if (part && part !== next[i].name) next[i] = { ...next[i], name: part };
              }
            }
            return next;
          });
        }
        return;
      }

      const d1 = data[1];
      const d2 = data.length > 2 ? data[2] : 0;
      const type = status & 0xf0;
      const channel = status & 0x0f;

      if (type === 0xD0) {
        if (channel < CHANNELS_COUNT) {
          setMeterLevels(prev => {
            const next = [...prev];
            next[channel] = d1;
            return next;
          });
        }
        return;
      }

      if (type === 0xE0) {
        if (channel < CHANNELS_COUNT && !isDragging.current[channel]) {
          setChannels(prev => {
            if (prev[channel].fader === d2) return prev;
            const next = [...prev];
            next[channel] = { ...next[channel], fader: d2 };
            return next;
          });
        }
      }

      else if (type === 0x90) {
        if (d1 >= 0x10 && d1 <= 0x17) setChannels(p => p.map((ch, i) => i === (d1 - 0x10) ? { ...ch, mute: d2 > 0 } : ch));
        if (d1 >= 0x08 && d1 <= 0x0F) setChannels(p => p.map((ch, i) => i === (d1 - 0x08) ? { ...ch, solo: d2 > 0 } : ch));
        if (d1 >= 0x00 && d1 <= 0x07) setChannels(p => p.map((ch, i) => i === (d1 - 0x00) ? { ...ch, rec: d2 > 0 } : ch));
        if (d1 === 0x5E) setIsPlaying(d2 > 0);
        if (d1 === 0x5F) setIsRecording(d2 > 0);
      }
    };

    input.onmidimessage = onMessage;
    return () => { input.onmidimessage = null; };
  }, [midiAccess, selectedInput]);

  const updateChannel = (id: number, updates: Partial<ChannelData>) => {
    if (updates.fader !== undefined) {
      isDragging.current[id] = true;
      if (lastSentValues.current[id] !== updates.fader) {
        lastSentValues.current[id] = updates.fader;
        sendMidi(0xE0 + id, 0, updates.fader);
      }
      const timerId = (window as any)[`fader_timer_${id}`];
      if (timerId) clearTimeout(timerId);
      (window as any)[`fader_timer_${id}`] = setTimeout(() => { isDragging.current[id] = false; }, 200);
    }

    if (updates.mute !== undefined) sendMomentaryButton(0x10 + id);
    if (updates.solo !== undefined) sendMomentaryButton(0x08 + id);
    if (updates.rec !== undefined) sendMomentaryButton(0x00 + id);
    if (updates.pan !== undefined) sendMidi(0xB0, 16 + id, updates.pan);

    if (updates.fader !== undefined || updates.pan !== undefined) {
        setChannels(prev => prev.map(ch => ch.id === id ? { ...ch, ...updates } : ch));
    }
  };

  const handleAiHelp = async () => {
    setIsAiLoading(true);
    const inPort = inputs.find(p => p.id === selectedInput)?.name || 'None';
    const outPort = outputs.find(p => p.id === selectedOutput)?.name || 'None';
    const query = `Setting up with In: ${inPort}, Out: ${outPort}. How do I fix connection issues?`;
    const help = await getMidiAssistance(query, mode);
    setAiResponse(help);
    setIsAiLoading(false);
  };

  const getInPortName = () => inputs.find(p => p.id === selectedInput)?.name || 'off';
  const getOutPortName = () => outputs.find(p => p.id === selectedOutput)?.name || 'off';
  const masterLevel = meterLevels.reduce((a, b) => a + b, 0) / CHANNELS_COUNT;

  return (
    <div className="flex flex-col h-screen overflow-hidden bg-[#0c0c0c] text-slate-200 font-sans">
      <header className="flex flex-col sm:flex-row items-center justify-between px-4 sm:px-6 py-2 sm:py-3 bg-[#181818] border-b border-black shadow-2xl z-10 gap-3">
        <div className="flex items-center gap-3 self-start sm:self-auto">
          <div className="w-10 h-10 bg-gradient-to-br from-[#526d4f] to-[#1a2b19] rounded-xl flex items-center justify-center text-white shadow-lg border border-[#ffffff10]">
            <i className="fas fa-sliders-h text-lg"></i>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none">Reaper<span className="text-[#526d4f]">Host</span></h1>
            <div className="flex items-center gap-2 mt-1">
              <div className={`w-1.5 h-1.5 rounded-full ${isReaperSynced ? 'bg-cyan-400' : 'bg-zinc-800'}`}></div>
              <p className={`text-[8px] font-black tracking-widest uppercase ${isReaperSynced ? 'text-cyan-400' : 'text-zinc-600'}`}>
                {isReaperSynced ? 'SYNCED' : 'LINK'}
              </p>
            </div>
          </div>
        </div>

        <div className="flex flex-wrap gap-2 items-center justify-end w-full sm:w-auto">
          <div className="flex gap-2">
            <select className="bg-black text-[10px] p-1.5 border border-[#333] rounded-lg w-28 sm:w-36 outline-none hover:border-[#526d4f]" value={selectedInput} onChange={e => setSelectedInput(e.target.value)}>
              <option value="">In: (None)</option>
              {inputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
            <select className="bg-black text-[10px] p-1.5 border border-[#333] rounded-lg w-28 sm:w-36 outline-none hover:border-[#526d4f]" value={selectedOutput} onChange={e => setSelectedOutput(e.target.value)}>
              <option value="">Out: (None)</option>
              {outputs.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
            </select>
          </div>
          <button onClick={() => setShowHelper(true)} className="bg-[#222] hover:bg-[#333] text-[#526d4f] p-2 rounded-lg transition-all border border-[#333]">
            <i className="fas fa-magic"></i>
          </button>
        </div>
      </header>

      <main className="flex-grow flex flex-col sm:flex-row p-2 sm:p-3 gap-2 sm:gap-3 overflow-hidden bg-[#080808]">
        <div className="flex-grow flex bg-[#121212] rounded-xl sm:rounded-2xl border border-[#222] shadow-inner overflow-x-auto custom-scrollbar overflow-y-hidden">
          {channels.map((ch) => (
            <div key={ch.id} className="min-w-[100px] sm:min-w-[110px] border-r border-black flex flex-col last:border-0 hover:bg-[#161616] transition-colors relative">
               <div className="p-3 bg-black/40 flex flex-col items-center gap-3 border-b border-black">
                 <Knob label="PAN" value={ch.pan} onChange={v => updateChannel(ch.id, { pan: v })} />
                 <div className="grid grid-cols-2 gap-1.5 w-full">
                   <button onClick={() => updateChannel(ch.id, { solo: !ch.solo })} className={`text-[10px] font-black py-1 rounded-md border transition-all ${ch.solo ? 'bg-yellow-600 border-yellow-400 text-black' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>S</button>
                   <button onClick={() => updateChannel(ch.id, { mute: !ch.mute })} className={`text-[10px] font-black py-1 rounded-md border transition-all ${ch.mute ? 'bg-red-700 border-red-500 text-white' : 'bg-zinc-800 border-zinc-700 text-zinc-500'}`}>M</button>
                 </div>
                 <button onClick={() => updateChannel(ch.id, { rec: !ch.rec })} className={`w-full text-[9px] font-black py-1.5 rounded-md border transition-all ${ch.rec ? 'bg-red-600 border-red-500 text-white animate-pulse' : 'bg-[#0a0a0a] border-zinc-800 text-red-900/40'}`}>REC</button>
               </div>
               <div className="flex-grow relative flex">
                 <Fader channelId={ch.id} label={ch.name} value={ch.fader} onChange={v => updateChannel(ch.id, { fader: v })} />
                 <div className="w-1 bg-black absolute right-1.5 top-8 bottom-8 rounded-full overflow-hidden flex flex-col justify-end">
                    <div className="bg-gradient-to-t from-green-500 via-yellow-500 to-red-500 w-full transition-all duration-75" style={{ height: `${(meterLevels[ch.id] / 127) * 100}%` }}></div>
                 </div>
               </div>
            </div>
          ))}
        </div>

        <aside className="h-auto sm:h-full w-full sm:w-40 lg:w-48 flex flex-col gap-2 sm:gap-3">
          <div className="flex-grow sm:flex-grow bg-[#181818] rounded-xl sm:rounded-2xl border border-[#222] p-3 sm:p-4 flex flex-col shadow-xl relative overflow-hidden min-h-[80px] sm:min-h-0">
            <h3 className="text-[9px] font-black text-[#526d4f] mb-2 sm:mb-3 uppercase tracking-widest border-b border-[#526d4f30] pb-2 flex justify-between items-center">
              <span>Master</span>
              {isReaperSynced && <i className="fas fa-bolt text-cyan-500 text-[8px]"></i>}
            </h3>
            <div className="flex-grow bg-black rounded-lg border border-[#000] p-2 flex items-end gap-1.5 relative overflow-hidden shadow-inner">
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded-sm transition-all duration-100" style={{ height: `${Math.max(2, (masterLevel / 127) * 98)}%` }}></div>
               <div className="flex-grow bg-gradient-to-t from-green-950 via-[#526d4f] to-red-600 rounded-sm transition-all duration-100" style={{ height: `${Math.max(2, (masterLevel / 127) * 94)}%` }}></div>
            </div>
          </div>

          <Transport 
            isPlaying={isPlaying} 
            isRecording={isRecording}
            onPlay={() => { setIsPlaying(true); sendMomentaryButton(0x5E); }}
            onStop={() => { setIsPlaying(false); setIsRecording(false); sendMomentaryButton(0x5D); }}
            onRec={() => { setIsRecording(!isRecording); sendMomentaryButton(0x5F); }}
            onPrev={() => sendMomentaryButton(0x5B)}
            onNext={() => sendMomentaryButton(0x5C)}
          />
        </aside>
      </main>

      <footer className="bg-[#050505] border-t border-[#181818] px-4 py-2 flex justify-between items-center text-[9px] font-black uppercase z-20 overflow-x-auto whitespace-nowrap gap-4">
        <div className="flex gap-4 items-center">
          <div className="flex items-center gap-2">
            <span className="text-zinc-600">IN:</span>
            <div className={`w-2 h-2 rounded-full ${midiInActive ? 'bg-[#526d4f]' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-500 font-mono truncate max-w-[80px]">{getInPortName()}</span>
          </div>
          <div className="flex items-center gap-2">
            <span className="text-zinc-600">OUT:</span>
            <div className={`w-2 h-2 rounded-full ${midiOutActive ? 'bg-cyan-500' : 'bg-zinc-900'}`}></div>
            <span className="text-zinc-500 font-mono truncate max-w-[80px]">{getOutPortName()}</span>
          </div>
        </div>
        <div className="flex gap-4 items-center">
           <span className="text-zinc-700 hidden sm:inline"><i className="fas fa-brain text-[#526d4f]"></i> AI READY</span>
           <div className={`px-3 py-1 rounded-full flex items-center gap-2 border ${midiAccess ? 'text-[#526d4f] border-[#526d4f30]' : 'text-red-700 border-red-900/30'}`}>
              <i className={`fas ${midiAccess ? 'fa-check' : 'fa-times'}`}></i>
              <span className="hidden xs:inline">{midiAccess ? 'DRIVER OK' : 'ERROR'}</span>
           </div>
        </div>
      </footer>

      {showHelper && (
        <div className="absolute inset-0 bg-black/98 backdrop-blur-2xl z-50 flex items-center justify-center p-4">
          <div className="bg-[#181818] max-w-2xl w-full rounded-3xl border border-[#333] shadow-2xl p-6 sm:p-10 relative overflow-hidden overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowHelper(false)} className="absolute top-6 right-6 text-zinc-500 hover:text-white"><i className="fas fa-times text-2xl"></i></button>
            <h2 className="text-2xl font-black text-[#526d4f] mb-6 uppercase italic flex items-center gap-3"><i className="fas fa-robot"></i> AI Setup</h2>
            <div className="grid grid-cols-1 gap-6 mb-6">
              <button 
                onClick={handleAiHelp} 
                disabled={isAiLoading}
                className="w-full bg-[#526d4f] py-3.5 rounded-2xl font-black uppercase text-white shadow-lg flex items-center justify-center gap-3 transition-all disabled:opacity-50"
              >
                {isAiLoading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-sparkles"></i>}
                {isAiLoading ? 'Analyzing...' : 'Generate Assistant Response'}
              </button>
              <div className="bg-black rounded-2xl border border-zinc-800 p-5 min-h-[200px] overflow-y-auto">
                <p className="text-[9px] font-black text-zinc-500 mb-3 uppercase tracking-widest border-b border-zinc-800 pb-2">Gemini Output</p>
                {aiResponse ? (
                  <div className="text-[12px] text-zinc-300 leading-relaxed space-y-3 font-mono">
                    {aiResponse.split('\n').map((line, i) => <p key={i}>{line}</p>)}
                  </div>
                ) : (
                  <p className="text-[11px] text-center text-zinc-700 mt-10">Waiting for AI request...</p>
                )}
              </div>
            </div>
            <button onClick={() => setShowHelper(false)} className="w-full border border-zinc-700 py-3 rounded-2xl font-black uppercase text-zinc-400">Close</button>
          </div>
        </div>
      )}
      <style>{`.custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; } .custom-scrollbar::-webkit-scrollbar-thumb { background: #333; border-radius: 10px; } .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #526d4f; }`}</style>
    </div>
  );
};

export default App;

import React from 'react';

interface TransportProps {
  isPlaying: boolean;
  isRecording: boolean;
  onPlay: () => void;
  onStop: () => void;
  onRec: () => void;
  onPrev: () => void;
  onNext: () => void;
}

const Transport: React.FC<TransportProps> = ({ 
  isPlaying, isRecording, onPlay, onStop, onRec, onPrev, onNext 
}) => {
  return (
    <div className="flex flex-col gap-2 sm:gap-3 bg-black/40 p-2 sm:p-3 rounded-xl border border-white/5 shadow-2xl">
      <div className="flex items-center justify-between gap-1">
        <button onClick={onPrev} className="flex-grow h-10 rounded-lg bg-zinc-900 hover:bg-zinc-800 flex items-center justify-center text-zinc-500 border border-zinc-800">
          <i className="fas fa-backward text-xs"></i>
        </button>
        <button 
          onClick={onStop} 
          className="flex-grow h-10 rounded-lg bg-zinc-900 hover:bg-zinc-800 flex items-center justify-center text-zinc-300 border border-zinc-800"
        >
          <i className="fas fa-stop text-xs"></i>
        </button>
        <button onClick={onNext} className="flex-grow h-10 rounded-lg bg-zinc-900 hover:bg-zinc-800 flex items-center justify-center text-zinc-500 border border-zinc-800">
          <i className="fas fa-forward text-xs"></i>
        </button>
      </div>

      <div className="flex items-center gap-2">
        <button 
          onClick={onPlay} 
          className={`flex-[2] h-12 rounded-xl flex items-center justify-center transition-all border ${isPlaying ? 'bg-green-600 border-green-400 text-white shadow-lg shadow-green-900/40' : 'bg-zinc-900 border-zinc-800 text-green-500'}`}
        >
          <i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'} text-sm`}></i>
        </button>

        <button 
          onClick={onRec} 
          className={`flex-grow h-12 rounded-xl flex items-center justify-center transition-all border ${isRecording ? 'bg-red-600 border-red-400 text-white animate-pulse' : 'bg-zinc-900 border-zinc-800 text-red-500'}`}
        >
          <i className="fas fa-circle text-xs"></i>
        </button>
      </div>

      <div className="py-2 bg-black/60 rounded-lg border border-white/5 text-center shadow-inner">
        <div className="text-[7px] text-zinc-600 uppercase font-black tracking-widest mb-0.5">Timecode</div>
        <div className="oled-display text-sm font-mono text-cyan-500/80">00:01:24:12</div>
      </div>
    </div>
  );
};

export default Transport;

